-- Poems batch 149
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('d5d590b3-c4e7-45f4-acea-bb4697ebe592','寄潘德久','許及之','宋','宋诗','song-poetry','','[]','新雨不可待，故人猶作疎。',48,'全唐诗/poet.song.152000.json','["新雨不可待，故人猶作疎。", "有方能煮字，無策與脂車。", "灑地親霜簟，敲冰想玉壺。", "端能乘月過，重賦碧芙蕖。"]'),
('0cf62851-824f-4b84-ac7f-26e4284e63b1','懷鄭仁叔  其一','許及之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','近有河魚疾，曾煩舊雨來。',48,'全唐诗/poet.song.152000.json','["近有河魚疾，曾煩舊雨來。", "又成三日別，未覺百懷開。", "氣合嗟同病，情親憶把杯。", "西湖荷蓋底，誰遣畫船回。"]'),
('2355c671-f37c-4b68-8f8d-41672ec81ac6','懷鄭仁叔  其二','許及之','宋','宋诗','song-poetry','','[]','斗大樓居窄，林深客思長。',48,'全唐诗/poet.song.152000.json','["斗大樓居窄，林深客思長。", "雨凉欣破甑，風急凜垂堂。", "倚祿生涯拙，憂時鬢髮蒼。", "向來遮日手，祇合釣滄浪。"]'),
('bd8268dc-6f37-4d65-ba76-4748f4570c8b','病足少蘇次常之韻三首  其一','許及之','宋','宋诗','song-poetry','','[]','攣拳尊足苦，伸縮楚囚聲。',48,'全唐诗/poet.song.152000.json','["攣拳尊足苦，伸縮楚囚聲。", "藥甲新條在，醫科舊貫盈。", "百年雙脚健，萬事一漚輕。", "獨恨忘形友，終然少合并。"]'),
('c66265de-0ddb-4ecf-8a98-2bbb0f86f8ce','病足少蘇次常之韻三首  其二','許及之','宋','宋诗','song-poetry','','[]','休從詹尹卜，數亦不難通。',48,'全唐诗/poet.song.152000.json','["休從詹尹卜，數亦不難通。", "寄祿逾三品，論才祇下中。", "器欹終必覆，藥裹漫成叢。", "痼疾元來有，惟知酒有功。"]'),
('1ff0f9e2-b6cb-4d76-98af-0e514eaa184d','病足少蘇次常之韻三首  其三','許及之','宋','宋诗','song-poetry','','[]','藍田紆古句，令我好懷開。',48,'全唐诗/poet.song.152000.json','["藍田紆古句，令我好懷開。", "未敢爲瓊報，何從引玉來。", "蒲萄江漲醁，桑落甕留醅。", "柳市人歸未，隨潮蚤晚催。"]'),
('de8b2c5d-e755-47b8-8873-c95ba0077348','三次澄鱗韻喜聞捷音','許及之','宋','宋诗','song-poetry','','[]','昨夜燈花喜，今朝吉語新。',48,'全唐诗/poet.song.152000.json','["昨夜燈花喜，今朝吉語新。", "犁庭真破竹，入境若無人。", "何力裨洪造，擎拳爇寶薰。", "從今願諸將，獻捷日頻頻。"]'),
('1180fe0e-5009-4c23-8bf3-a88c476f0012','四次聞捷韻','許及之','宋','宋诗','song-poetry','','[]','身閒偏蚤起，邊報逐朝新。',48,'全唐诗/poet.song.152000.json','["身閒偏蚤起，邊報逐朝新。", "諸將休輕敵，中原尚有人。", "定須申撻伐，安得雜蕕薰。", "祇愧渾無補，空歌捷詠頻。"]'),
('d0ec1973-5b78-43bc-8b43-ffb37b6adbf8','聞捷五次轉庵韻','許及之','宋','宋诗','song-poetry','','[]','周歷綿綿遠，湯盤日日新。',48,'全唐诗/poet.song.152000.json','["周歷綿綿遠，湯盤日日新。", "恭聞哀痛詔，憤激老癃人。", "報答带仍礪，英雄沐更薰。", "衰年扶杖聽，折屐敢辭頻。"]'),
('ab631e0a-5a8f-41d8-9c6d-e172cbf94549','轉庵催結局六次韻','許及之','宋','宋诗','song-poetry','','[]','漢儀重睹舊，秦暴盡更新。',48,'全唐诗/poet.song.152000.json','["漢儀重睹舊，秦暴盡更新。", "應是天亡敵，從知國有人。", "乾坤大開闢，華夏一陶薰。", "收到崑崙北，詩應快李頻。"]'),
('0da1edf5-d619-46e9-ba91-9c58a35d9154','和轉庵與洪共之說詩談禪之什','許及之','宋','宋诗','song-poetry','','[]','鐺坐聽清話，鼎來宜笑譁。',48,'全唐诗/poet.song.152000.json','["鐺坐聽清話，鼎來宜笑譁。", "詩談五字律，禪說一枝花。", "未肯傳衣鉢，先須借齒牙。", "老婆心更切，黄檗正栽茶。"]'),
('a266ef9c-36ed-479d-8c5f-9ceb635b046b','又再和轉庵且置詩話聊答說禪之什','許及之','宋','宋诗','song-poetry','','[]','見性元非說，傳心豈得譁。',48,'全唐诗/poet.song.152000.json','["見性元非說，傳心豈得譁。", "三更親受法，五葉自開花。", "雖遇奪衣嶺，終摇度艣牙。", "要知觀自在，不異鳩盤茶。"]'),
('57d27b71-d77d-4bb0-a5b5-d9fd738dccd6','又復次韻爲酬答說禪偈言','許及之','宋','宋诗','song-poetry','','[]','密傳當正受，諦聽勿高譁。',48,'全唐诗/poet.song.152000.json','["密傳當正受，諦聽勿高譁。", "要結菩提果，須開頓悟花。", "祖師禪上陣，大將擁高牙。", "赴了齋時飯，大家同喫茶。"]'),
('3a9cc5c2-4f63-4113-806b-ff6244d59db8','次外舅遣侍人韻','許及之','宋','宋诗','song-poetry','','[]','關中蕭相國，江左管夷吾。',48,'全唐诗/poet.song.152000.json','["關中蕭相國，江左管夷吾。", "人仰高山石，心宜赤水珠。", "登臨捐妓女，書札付官奴。", "妙得安心法，繩床底用蒲。"]'),
('93cc73fd-8fe0-44d5-818c-2da531d2a922','再次外舅韻戲呈舍人叔丈','許及之','宋','宋诗','song-poetry','','[]','接棟兄過弟，忘懷汝與吾。',48,'全唐诗/poet.song.152000.json','["接棟兄過弟，忘懷汝與吾。", "纏頭新辦錦，買笑近量珠。", "怒釋泥中婢，歡全膝下奴。", "使無驅豆法，亦合賭樗蒱。"]'),
('8a348668-1a36-4427-bdd3-599a0b973b34','次外舅聞字即事韻','許及之','宋','宋诗','song-poetry','','[]','蘧瑗行年化，宣尼耳順聞。',48,'全唐诗/poet.song.152000.json','["蘧瑗行年化，宣尼耳順聞。", "聲名昭白日，富貴薄浮雲。", "天子方嘗膽，中原未靜氛。", "加餐爲時起，禮樂不徒云。"]'),
('541160a7-fc88-4e26-98c1-d654cb96e2a6','再次韻并呈舍人叔丈','許及之','宋','宋诗','song-poetry','','[]','過訪鄰牆近，歌呼隔屋聞。',48,'全唐诗/poet.song.152000.json','["過訪鄰牆近，歌呼隔屋聞。", "江收梅熟雨，川映蕊紅雲。", "把燭杯仍艷，交談篆接氛。", "盤洲餘醉墨，吾亦欲云云。"]'),
('e9bd590b-aee3-475f-b213-9bbac9dadf7b','再次聞字韻','許及之','宋','宋诗','song-poetry','','[]','船屋香留潤，衣篝冷却聞。',48,'全唐诗/poet.song.152000.json','["船屋香留潤，衣篝冷却聞。", "晚山新見月，別浦宿藏雲。", "歲月催人老，江湖凈世氛。", "望中愁不極，收拾費詩云。"]'),
('b5d2c7a7-c606-4ba6-a152-5db4fce63587','次韻德久','許及之','宋','宋诗','song-poetry','','[]','熟闚齊物論，懶賦畔牢愁。',48,'全唐诗/poet.song.152000.json','["熟闚齊物論，懶賦畔牢愁。", "浮世夢槐國，虛名種橘侯。", "有身俱有患，無累即無求。", "不啻如今足，何如取次休。"]'),
('82f96974-f2c6-46b5-917e-f0451c5e84ae','次轉庵韻  其一','許及之','宋','宋诗','song-poetry','','[]','節中期樂事，座上欠嘉賓。',48,'全唐诗/poet.song.152000.json','["節中期樂事，座上欠嘉賓。", "雨帽何妨濕，雲山自带顰。", "午晴開喜色，歸月入懷新。", "有菊皆重九，無須更卜辰。"]'),
('fbc087c3-1977-4377-a8ea-39d0cc044a95','次轉庵韻  其二','許及之','宋','宋诗','song-poetry','','[]','有約惟真率，相忘任主賓。',48,'全唐诗/poet.song.152000.json','["有約惟真率，相忘任主賓。", "拒霜方送喜，疎柳不爭顰。", "近復關原舊，頻看邸報新。", "吾儕何幸甚，投老得逢辰。"]'),
('b944c0e5-5bc4-4bd5-9778-f2b93a4b4afe','三次轉庵韻仍招小飲','許及之','宋','宋诗','song-poetry','','[]','有徑望三益，杜門無雜賓。',48,'全唐诗/poet.song.152000.json','["有徑望三益，杜門無雜賓。", "只逢開口笑，絕勝捧心顰。", "一色黄華在，雙投白醖新。", "速宜相爾汝，元不闊參辰。"]'),
('cea572d6-fcd4-417c-8530-fdda4a4ff2dc','金魚久不浮游喜而有作','許及之','宋','宋诗','song-poetry','','[]','買得黄金鯽，投將白玉池。',48,'全唐诗/poet.song.152000.json','["買得黄金鯽，投將白玉池。", "久晴虞涸轍，轉壑漾深陂。", "每施龜魚食，偏懷網罟疑。", "今晨水澄澈，梭影泛琉璃。"]'),
('a77cd010-4af8-45a7-a51e-144e933ca7bd','有喜真愛亭梅花開走筆呈轉庵','許及之','宋','宋诗','song-poetry','','[]','小園饒勝事，僮僕競讙譁。',48,'全唐诗/poet.song.152000.json','["小園饒勝事，僮僕競讙譁。", "梅綻凌寒樹，枝繁照水花。", "病身俄勿藥，詩思頓萌芽。", "急報南鄰友，新篘可當茶。"]'),
('1900ff27-0c72-40c0-9dbf-673e5d9ca9ed','白山茶','許及之','宋','宋诗','song-poetry','','[]','白茶誠異品，天賦玉玲瓏。',48,'全唐诗/poet.song.152000.json','["白茶誠異品，天賦玉玲瓏。", "不作燒燈焰，深明韞櫝功。", "易容非世力，幻質本春工。", "皓皓知難污，塵飛漫自紅。"]'),
('545c6435-a85a-465e-a9a4-2292e6bc1362','和轉庵白蓮','許及之','宋','宋诗','song-poetry','','[]','虛籟一聲蟬，通宵月正懸。',48,'全唐诗/poet.song.152000.json','["虛籟一聲蟬，通宵月正懸。", "亭亭承露掌，歷歷涉波仙。", "夜色起香霧，曉光收玉烟。", "層冰不可致，清賦憶前年。"]'),
('1028f415-3542-4d80-b19a-5670dda782e0','諸葛忠叟初逢家墊池中産雙蓮求予扁榜併作五言勉諸甥','許及之','宋','宋诗','song-poetry','','[]','我愛濂溪說，君能喜種蓮。',48,'全唐诗/poet.song.152000.json','["我愛濂溪說，君能喜種蓮。", "一經初建塾，雙實遽呈川。", "和氣壎箎應，榮名棣萼聯。", "勉旃成宅相，學也是家傳。"]'),
('e483a2dd-039b-4c78-8fc1-697cc1623ba1','麝香萱','許及之','宋','宋诗','song-poetry','','[]','南薰吹麝馥，背樹染鵝黄。',48,'全唐诗/poet.song.152000.json','["南薰吹麝馥，背樹染鵝黄。", "裏許香爲德，中央色自莊。", "洛津行夕佩，仙掌洗晨粧。", "真爲忘憂賞，看雲戀故鄉。"]'),
('4393843a-c3c0-49a7-bc3e-1bb22067ffd9','煮茗  其一','許及之','宋','宋诗','song-poetry','','[]','止酒身多病，添書日正長。',48,'全唐诗/poet.song.152000.json','["止酒身多病，添書日正長。", "睡魔推不去，茗碗熟難忘。", "鵲過飛樵墮，蜂喧落粉香。", "靜中觀物理，此樂未渠央。"]'),
('d8cf0a9e-398c-479c-87ed-98a6d2bf2899','煮茗  其二','許及之','宋','宋诗','song-poetry','','[]','煮茗鴉闚井，哦詩蝶過垣。',48,'全唐诗/poet.song.152000.json','["煮茗鴉闚井，哦詩蝶過垣。", "笋高垂籜瘦，梅落墜枝繁。", "白晝重闈靜，新晴遠市喧。", "境緣看漸熟，吾亦欲忘言。"]'),
('292ea5db-9f3d-4d45-8d02-84539d190f11','顯庵餉伊蒲索著語代簡','許及之','宋','宋诗','song-poetry','','[]','却埽銷長夏，來薰傍曲肱。',48,'全唐诗/poet.song.152000.json','["却埽銷長夏，來薰傍曲肱。", "轆轤金井水，沆瀣玉壺冰。", "避暑元無法，安心却粗能。", "破除香積飯，供給在家僧。"]'),
('789bf1d1-e4db-466e-ba21-608ad9d8aa2a','輓故丈母萊國夫人沈氏三首  其一','許及之','宋','宋诗','song-poetry','','[]','北使復南遷，尚書大節全。',48,'全唐诗/poet.song.152000.json','["北使復南遷，尚書大節全。", "長公身致相，冢婦世稱賢。", "象服宜偕老，魚軒遽溘先。", "哀傷動行路，謝傅况中年。"]'),
('256db983-2aa3-4f3b-b0f8-c27f3fab34ed','輓故丈母萊國夫人沈氏三首  其二','許及之','宋','宋诗','song-poetry','','[]','林泉當絲竹，丞相巧安貧。',48,'全唐诗/poet.song.152000.json','["林泉當絲竹，丞相巧安貧。", "珍重承夫意，清修報主身。", "指千隨嗜好，體一寫姻親。", "更有銜恩者，妻孥寄食頻。"]'),
('984394a4-b11a-4af7-99e0-ecd6ce68774b','輓故丈母萊國夫人沈氏三首  其三','許及之','宋','宋诗','song-poetry','','[]','愛女終身託，嬰兒半路遺。',48,'全唐诗/poet.song.152000.json','["愛女終身託，嬰兒半路遺。", "訃音非不達，憂思恐難支。", "已及黄泉見，應憐白首期。", "愛恩均罔極，淚盡輓歌詞。"]'),
('1979aa6b-1c14-4386-bdab-be3a2b9719e6','元日登天長縣城','許及之','宋','宋诗','song-poetry','','[]','元日登臨一腐儒，感今懷昔愧微軀。',64,'全唐诗/poet.song.152000.json','["元日登臨一腐儒，感今懷昔愧微軀。", "此城曾是千秋縣，有水呼爲萬歲湖。", "南渡向來紆翠駕，北征何日會京都。", "祖功宗德無邊際，可恨長淮限一隅。"]'),
('0b805b0c-2d6f-4d12-9206-339209e0e3c2','次常之元日復用韻','許及之','宋','宋诗','song-poetry','','[]','椒花祝處羽觴飛，第一春光勿願違。',64,'全唐诗/poet.song.152000.json','["椒花祝處羽觴飛，第一春光勿願違。", "已是浹旬彈指過，可堪維暮轉頭非。", "詩籤絡繹須盈袖，酒醆淋漓聽滿衣。", "老去寸陰尤愛惜，久拚带減沈郎圍。"]'),
('79f8c332-a732-4b7d-b955-94c5cbbc6f39','人日用常之韻寄才叔居甫','許及之','宋','宋诗','song-poetry','','[]','斷腸梅作雪紛飛，似與金花巧勝違。',64,'全唐诗/poet.song.152000.json','["斷腸梅作雪紛飛，似與金花巧勝違。", "此日共憐人日是，今春誰道我春非。", "閒中風月爲蓮社，醉裏鶑花即錦衣。", "題寄草堂須記取，莫孤綠繞惜紅圍。"]'),
('b978e475-98ef-4d03-9acd-f04738a34ab6','人日','許及之','宋','宋诗','song-poetry','','[]','明當春日今人日，身到故鄉勝異鄉。',64,'全唐诗/poet.song.152000.json','["明當春日今人日，身到故鄉勝異鄉。", "巧勝耐寒元故事，青絲傳菜舊風光。", "只將柏葉聊隨酒，莫爲梅花苦斷腸。", "南北兩園多種接，閒居從此有閒忙。"]'),
('25ca136f-2544-433d-bca1-28fad6d776cd','次韻宣甫約元宵入城不至','許及之','宋','宋诗','song-poetry','','[]','春已兼旬未脫綿，積陰頓掃柳條烟。',64,'全唐诗/poet.song.152000.json','["春已兼旬未脫綿，積陰頓掃柳條烟。", "兒童戲放摶風鴿，老子惟看跕水鳶。", "剪綵試燈新樂事，逢場作戲舊豐年。", "詩翁不離陶溪隠，可是公房戀屋仙。"]'),
('34c23fe4-e321-410e-99ba-217ab1d857e8','王宣甫以燈夕入城而予偶無佳思阻同遊有詩爲寒食之約次韻奉酬','許及之','宋','宋诗','song-poetry','','[]','落梅聲裏惜餘芳，孤負燈光與月光。',64,'全唐诗/poet.song.152000.json','["落梅聲裏惜餘芳，孤負燈光與月光。", "偶以催租敗佳思，阻隨執事佐顔行。", "春風已入青絲鞚，好句終歸古錦囊。", "能踐清明重約否，須知歲月去堂堂。"]'),
('36e415fe-9141-4e55-b6b1-43ff2e79213f','元夕之明日久陰乍晴月色皎然','許及之','宋','宋诗','song-poetry','','[]','連陰乍霽自新元，細雨梅花自可憐。',64,'全唐诗/poet.song.152000.json','["連陰乍霽自新元，細雨梅花自可憐。", "天意肯教人悵望，燈宵終放月團圓。", "兒童鼓舞幾通夕，我輩歡呼竟不眠。", "老少相懸均此樂，去秋無此大豐年。"]'),
('69def2b5-3991-4696-8774-ef328db0398d','次韻程判院春日','許及之','宋','宋诗','song-poetry','','[]','催得冬殘是野梅，依然春傍柳邊回。',64,'全唐诗/poet.song.152000.json','["催得冬殘是野梅，依然春傍柳邊回。", "不知鬢影星星去，只道年光恰恰來。", "喜爲農占秋有廩，懶于僧問劫經灰。", "歷頭且復從今數，笑口都能幾度開。"]'),
('dfef36a0-e98c-40c8-b090-de663188c995','二月晦日游木瓜園','許及之','宋','宋诗','song-poetry','','[]','亭成寄樂小裴回，野水粼粼傍酒杯。',64,'全唐诗/poet.song.152000.json','["亭成寄樂小裴回，野水粼粼傍酒杯。", "未有政聲追召杜，敢將詩律繼歐梅。", "春風已辦催花絮，夜雨惟憐老菜臺。", "百二十春今恰半，不須扁榜記曾來。"]'),
('88555c3c-0019-49e4-80f5-fdd48b29f6aa','次韻謝余伯益節推','許及之','宋','宋诗','song-poetry','','[]','鵲喜聲頻去復回，亭成報我趣銜杯。',64,'全唐诗/poet.song.152000.json','["鵲喜聲頻去復回，亭成報我趣銜杯。", "春風得意矜新柳，野水留春戀落梅。", "何處笙歌催院落，一時車馬走輿臺。", "攙先但得邦人樂，待約鶑花殿後來。"]'),
('c4c6312e-583f-4f8a-86a9-5e4dcad4ebf1','次韻謝劉太丞','許及之','宋','宋诗','song-poetry','','[]','世事羊腸有幾回，功名隨意芥爲杯。',64,'全唐诗/poet.song.152000.json','["世事羊腸有幾回，功名隨意芥爲杯。", "放教春色歸繁杏，禁得東風是落梅。", "天上有人調玉燭，邊頭何地築金臺。", "朝廷仄席思耆舊，詔逐陽和蚤晚來。"]'),
('dc3491e3-fcc3-44dc-b70b-f61e385345f8','寒食日宿蕪湖縣廨','許及之','宋','宋诗','song-poetry','','[]','今年歧路足生涯，寒食蕪湖感物華。',64,'全唐诗/poet.song.152000.json','["今年歧路足生涯，寒食蕪湖感物華。", "少爲顔公成且住，絕憐杜老嘆無家。", "光風不禁吹香草，薄霧無端羃晚華。", "已是惜春那惜別，無多酌我怕周遮。"]'),
('5a0c7068-407b-4b52-8721-e0a831eb0b15','感春呈同社','許及之','宋','宋诗','song-poetry','','[]','靜處聊將物理推，鳥啼花發苦因誰。',64,'全唐诗/poet.song.152000.json','["靜處聊將物理推，鳥啼花發苦因誰。", "留連春事惟紅藥，管當行人是子規。", "莫道柳綿無住相，也爲萍絮媚清漪。", "如何飽食閒終日，不課離騷不賦詩。"]'),
('686ea8e2-5c7a-496f-bcc7-ef5e312bf25b','四月晦日袁起巖同年雨中集聚景園','許及之','宋','宋诗','song-poetry','','[]','湖上名園屬內家，湖邊有客誤乘槎。',64,'全唐诗/poet.song.152000.json','["湖上名園屬內家，湖邊有客誤乘槎。", "風餐歷歷秦宮樹，雨立亭亭漢節花。", "樂事坐來添晷刻，題名帖後带烟霞。", "春衫溼却它年話，合有新詩記物華。"]'),
('78636fbb-4c7b-4998-8a10-56939fca116e','次韻常之五日禁競渡','許及之','宋','宋诗','song-poetry','','[]','仍年此足爲吾病，舉世誰人似我閒。',64,'全唐诗/poet.song.152000.json','["仍年此足爲吾病，舉世誰人似我閒。", "思遠樓前重禁渡，容成洞裏獨看山。", "交游雨絕梅還溽，賡倡星分稿自刪。", "頼有松廬相慰藉，新篇時復到榆關。"]'),
('98660698-fbd4-4af0-a8e1-b40378bdb06c','閏上澣同德久子侄輩避暑退居即事','許及之','宋','宋诗','song-poetry','','[]','說著退居心已愜，湖山何况傍繩牀。',64,'全唐诗/poet.song.152000.json','["說著退居心已愜，湖山何况傍繩牀。", "雖無瑟瑟松杉韻，自覺愔愔枕簟凉。", "茗碗親來詩有思，藕花多處語猶香。", "一旬一日恩休沐，今日恩隨日更長。"]'),
('428c96f1-560b-484b-b527-666a731b9045','再賦紀實','許及之','宋','宋诗','song-poetry','','[]','官身不辦游山具，只有茶鐺與筆牀。',64,'全唐诗/poet.song.152000.json','["官身不辦游山具，只有茶鐺與筆牀。", "旋買鱸魚供箸美，却携玉友待樽涼。", "同來稚子聽情話，更有幽僧炷妙香。", "遥望畫船雲錦外，好風吹到笛聲長。"]'),
('c436520c-384b-4a58-853e-275a81ba9007','次韻酬張巖卿七夕','許及之','宋','宋诗','song-poetry','','[]','星文人事古難磨，女織男耕力最多。',64,'全唐诗/poet.song.152000.json','["星文人事古難磨，女織男耕力最多。", "河鼓有神司带犢，天孫垂象驗飛梭。", "因依鴻烈成橋語，泛濫長生舊殿歌。", "伉儷流傳鈞是褻，玉川無頼太風波。"]'),
('f6c33817-8fe3-49ee-898d-c7365a6a7418','次韻王宣甫秋夜書懷','許及之','宋','宋诗','song-poetry','','[]','靜聽高梧落甃聲，遥聞叢雀轉秋更。',64,'全唐诗/poet.song.152000.json','["靜聽高梧落甃聲，遥聞叢雀轉秋更。", "星隨斗極看時改，露濕天河徹底清。", "老去心情惟藥裹，病蘇燈火愜書檠。", "故人忽起關河思，觸撥深愁怒癭生。"]'),
('b8ce392b-b4f9-4a07-be1f-f757be4aa192','次韻陳仲全秋懷','許及之','宋','宋诗','song-poetry','','[]','一夜炎歊破甑空，蕭然秋思雨聲中。',64,'全唐诗/poet.song.152000.json','["一夜炎歊破甑空，蕭然秋思雨聲中。", "江湖兩鬢驚飛葉，歲月一身俱轉蓬。", "我自由來爲性癖，子今無乃坐詩窮。", "男兒窮達終相似，却是難教鑿枘同。"]'),
('2f39f860-06dd-474e-a99c-1c401f088785','九日次常之柳市秋懷韻','許及之','宋','宋诗','song-poetry','','[]','柳市留連愛別坰，歸來詩與字俱清。',64,'全唐诗/poet.song.152000.json','["柳市留連愛別坰，歸來詩與字俱清。", "閒居揫斂全生理，老境行藏見物情。", "恨把菊花隨雨過，醉敲瓦缶作雷鳴。", "千年張翰風流句，却是生前不願名。"]'),
('9f770529-96ce-43bf-9b54-c4caf833a516','次韻才叔九日家宴阻訪媚川','許及之','宋','宋诗','song-poetry','','[]','一秋天氣屬吟家，九日風光愛物華。',64,'全唐诗/poet.song.152000.json','["一秋天氣屬吟家，九日風光愛物華。", "對婦舉杯勝俗客，逢辰得酒值黄花。", "大難富有成糜季，小異誰知落帽嘉。", "獨坐媚川空悵望，半蟾分挂夕陽斜。"]'),
('c4586085-5e3c-4704-9221-ccfe42281a7f','次才叔和龔司令九日韻','許及之','宋','宋诗','song-poetry','','[]','滿院西風把菊天，官身閒暇亦悠然。',64,'全唐诗/poet.song.152000.json','["滿院西風把菊天，官身閒暇亦悠然。", "恍思杜老浮舟日，絕勝彭城戲馬年。", "豈待白衣開笑口，不妨烏帽庇華顛。", "却愁明發還多事，詩在龍山落照邊。"]'),
('1481682c-5d8e-47ea-8743-0968ecf0a4e2','九日簡德久','許及之','宋','宋诗','song-poetry','','[]','登高每恨尊無酒，近節今欣菊繞籬。',64,'全唐诗/poet.song.152000.json','["登高每恨尊無酒，近節今欣菊繞籬。", "風日正佳關氣數，心情不分減年時。", "愛將雪鬢欹紗帽，愜把霜螯對酒巵。", "意到潘郎寧易敗，催租端自不妨詩。"]'),
('c94e04f9-388d-4c8c-812a-305c0e6af2c6','次轉庵九日韻','許及之','宋','宋诗','song-poetry','','[]','窗前白白黄黄菊，門外疎疎短短籬。',64,'全唐诗/poet.song.152000.json','["窗前白白黄黄菊，門外疎疎短短籬。", "擇勝任從追賞日，有年即是太平時。", "呼鷹戲馬人千古，綴席浮舟酒一巵。", "五百年間張翰句，風流猶待謫仙詩。"]'),
('d724350b-6b68-491c-8e46-f5e752e7ea83','九日小飲用後山居士韻簡轉庵','許及之','宋','宋诗','song-poetry','','[]','連日欣晴卜暮霞，晨曦閃閃舞羣鴉。',64,'全唐诗/poet.song.152000.json','["連日欣晴卜暮霞，晨曦閃閃舞羣鴉。", "時豐都市人多醉，節近重陽菊有花。", "萬事悠然山正好，三杯可以我何加。", "自憐猶有童心在，愛把茱萸繫絳紗。"]'),
('d8e2c731-beee-49b6-a076-5208507ce664','再用後山韻','許及之','宋','宋诗','song-poetry','','[]','懶惰無心賦落霞，醉餘吟筆大如鴉。',64,'全唐诗/poet.song.152000.json','["懶惰無心賦落霞，醉餘吟筆大如鴉。", "但欣有酒酬佳節，猶勝無錢對菊花。", "小異孟嘉今老去，知非蘧瑗歎年加。", "登臨無奈秋光好，歸傍窗前月印紗。"]'),
('63f04bd2-7552-4935-a69d-b13dfbbd21ab','九日同從班諸公自南山過蘇堤登寶叔塔','許及之','宋','宋诗','song-poetry','','[]','柳下芙蓉錦作裳，畫船波底見秋光。',64,'全唐诗/poet.song.152000.json','["柳下芙蓉錦作裳，畫船波底見秋光。", "登高自昔須吾輩，戲馬從人上寶坊。", "白髮未嫌紗帽黑，紫萸偏稱菊花黄。", "常年風日無如此，爭不從容入醉鄉。"]'),
('449545fd-f200-42c6-a4fe-6d9e51088b49','次韻解頤叟九日登樓唐律二首  其一','許及之','宋','宋诗','song-poetry','','[]','詩翁九日獨登樓，悵望當年淺碧洲。',64,'全唐诗/poet.song.152000.json','["詩翁九日獨登樓，悵望當年淺碧洲。", "菊徑全稀虛過節，橘鄉無術敢當侯。", "漢庭非晚咨良策，邊算於今待遠籌。", "曾得合肥家信否，未應胡越可同舟。"]'),
('b3615257-dd11-4bf0-99b5-5a3971163876','次韻解頤叟九日登樓唐律二首  其二','許及之','宋','宋诗','song-poetry','','[]','規橅器業足資身，合是蘭宮第一人。',64,'全唐诗/poet.song.152000.json','["規橅器業足資身，合是蘭宮第一人。", "風月難兄居半刺，文章經國肯全貧。", "身丁近免家家喜，首述長謠句句新。", "預卜他時康濟事，定應不負白綸巾。"]'),
('a3bb147e-6384-4594-b492-25b5f9ea0799','三月二十七日玉堂夜宿','許及之','宋','宋诗','song-poetry','','[]','以玉爲堂未是誇，金林禽謝有金沙。',64,'全唐诗/poet.song.152000.json','["以玉爲堂未是誇，金林禽謝有金沙。", "稍傳禁漏提初點，旋聽周廬遞晚衙。", "春盡猶寒欺夢草，晴多未雨渴簷花。", "自憐雖是文章力，肯把凡駑污白麻。"]'),
('1bb2bd0f-bbce-4c1a-b8c3-7d3c59c7d18c','玉堂宿直次高內翰九日前一日草妃子麻畢題案上韻','許及之','宋','宋诗','song-poetry','','[]','歲稔時和庶事康，未央稱壽捧瑶觴。',64,'全唐诗/poet.song.152000.json','["歲稔時和庶事康，未央稱壽捧瑶觴。", "宣將鑾殿金爲炬，草就麻詞玉作堂。", "自是關雎思淑女，不同飛燕在昭陽。", "儒臣信得文章力，捧賜看花一樣黄。"]'),
('cc6c45a0-7153-4e80-a77c-92be8d6fa684','宿社祭齋宮與張野夫廨舍爲鄰信筆代簡','許及之','宋','宋诗','song-poetry','','[]','經時不見小于湖，已覺心源少轆轤。',64,'全唐诗/poet.song.152000.json','["經時不見小于湖，已覺心源少轆轤。", "漫道齋宮鄰廨宇，何殊弱水隔蓬壺。", "清談每想追前輩，快覩何從換故吾。", "大阮端憂更堪憶，平安曾得近書無。"]'),
('b2eed533-436f-4c16-8cda-42c78e862de5','九月十一日龍華寺齋宿禮部陳同年見余嵬字韻詩寵和惠示復用韻奉酬','許及之','宋','宋诗','song-poetry','','[]','鴈塔同登驚歲月，龍華共事陟崔嵬。',64,'全唐诗/poet.song.152000.json','["鴈塔同登驚歲月，龍華共事陟崔嵬。", "詩從瑞錦窠中出，人是黄花節後來。", "顧我何堪毗右府，如公端合上東臺。", "清時勝日才兼美，平步功名不用催。"]'),
('5bffeb64-ce7a-428d-89d4-b5fb99ea3fee','陳同年再次韻爲謝而王才叔判院和篇繼至復用韻併謝','許及之','宋','宋诗','song-poetry','','[]','鐺坐齋宮喜敬陪，高軒二妙屹崔嵬。',64,'全唐诗/poet.song.152000.json','["鐺坐齋宮喜敬陪，高軒二妙屹崔嵬。", "舊詩古廟香爐去，新句風檣陣馬來。", "但有黄花堪落帽，不應白髮怕登臺。", "留連月色須明發，未受秋更密點催。"]'),
('f68ffad5-a0d1-49a8-a93c-f7eddf40d736','酬才叔再用韻','許及之','宋','宋诗','song-poetry','','[]','三日齋餘過九日，今朝方得上崔嵬。',64,'全唐诗/poet.song.152000.json','["三日齋餘過九日，今朝方得上崔嵬。", "日隨鴻影翩翩去，句逐湖聲衮衮來。", "肯爲龍華留勝蹟，何須戲馬羨高臺。", "黄花未必相欺得，正要詩翁著句催。"]'),
('8e1c1d48-3145-4dbd-9815-0e7a997ec115','致齋禱雨次轉庵韻','許及之','宋','宋诗','song-poetry','','[]','夏中春閏合炎蒸，何事凉風日夜清。',64,'全唐诗/poet.song.152000.json','["夏中春閏合炎蒸，何事凉風日夜清。", "大旱望霓如許切，密雲不雨太無情。", "何妨閉閣齋三日，有愧聞蟬第一聲。", "遥想轉庵同此際，苦辭猶作渴蛙鳴。"]'),
('87e7aee0-6f9d-4dbc-9e92-22e4b7ca4dc7','祭龍前一日致齋雨大作邑人以爲數年未之有也作此呈養正明府','許及之','宋','宋诗','song-poetry','','[]','齋宿臨場早有期，邑官齊出去陪祠。',64,'全唐诗/poet.song.152000.json','["齋宿臨場早有期，邑官齊出去陪祠。", "祇應日脚埋雲處，便是山頭戴帽時。", "此雨近來都未有，豐年向去更無疑。", "請公買取千鍾酒，從此琴堂日展眉。"]'),
('0ab5ad78-3e07-465d-b783-6917873243a8','次韻廣文賀太守祈雨感應','許及之','宋','宋诗','song-poetry','','[]','天上爲霖正玉衡，農家占雨驗書檠。',64,'全唐诗/poet.song.152000.json','["天上爲霖正玉衡，農家占雨驗書檠。", "黄堂懇惻煩精禱，綠野歡呼得遍耕。", "束晳未遊猶要雨，蘇端好過莫教晴。", "廣文飯足渾閒事，吉語時聞更動情。"]'),
('af105abf-211a-4291-8f49-41c667154ba5','驟雨忽至','許及之','宋','宋诗','song-poetry','','[]','未茨山宇趣儲材，屐齒憐穿稱意苔。',64,'全唐诗/poet.song.152000.json','["未茨山宇趣儲材，屐齒憐穿稱意苔。", "礎石潤時雲氣動，茶烟凝處雨聲來。", "蠶家次第三眠柳，江國凄凉五月梅。", "電脚未收雷殷殷，老農爭不笑顔開。"]'),
('8884f246-5579-40f8-9550-9780978b3bc9','舟中喜雨','許及之','宋','宋诗','song-poetry','','[]','驟雨飈風趁急雷，畫船繫纜小裴回。',64,'全唐诗/poet.song.152000.json','["驟雨飈風趁急雷，畫船繫纜小裴回。", "隔簾大點欺窗紙，入戶微篩供酒杯。", "一夏屢憂無計奈，半秋頻喜傍懷來。", "世間好事無全美，濡首牽夫可念哉。"]'),
('7d3ed904-be11-4878-a17d-863b901669e3','積雨簡百七丈郎中二首  其一','許及之','宋','宋诗','song-poetry','','[]','鄉里從游不乏賢，薛侯令我自拳拳。',64,'全唐诗/poet.song.152000.json','["鄉里從游不乏賢，薛侯令我自拳拳。", "筆端有力能扛鼎，飲量無涯可吸川。", "寧屈乘軺紆郡紱，豈容謝事引官年。", "皇天有眼難從欲，暫許祠庭作散仙。"]'),
('2b129549-987f-4fee-a176-4a8d8ef9524a','積雨簡百七丈郎中二首  其二','許及之','宋','宋诗','song-poetry','','[]','社中真率數追陪，合有閒緣带得來。',64,'全唐诗/poet.song.152000.json','["社中真率數追陪，合有閒緣带得來。", "十日頓疎新舊雨，百年猶負淺深杯。", "護持盧橘黄金實，準擬榴花絳雪醅。", "但有菖蒲皆是節，不須端午始歡咍。"]'),
('28f9e76d-f79c-4bbf-8d36-b792e1ea3e9e','新晴','許及之','宋','宋诗','song-poetry','','[]','兩旬衰病與陰霖，徒有幽園日涉心。',64,'全唐诗/poet.song.152000.json','["兩旬衰病與陰霖，徒有幽園日涉心。", "曉色半窗驚睡起，鳥聲叢樹索詩尋。", "熙怡意象池亭滿，履歷工夫杖屨深。", "掉脫烏巾向人說，市朝不樂似山林。"]'),
('b959846d-7ff7-425e-bba6-3fdd47f0e44a','次韻劉參議喜得雪','許及之','宋','宋诗','song-poetry','','[]','勒回羲馭感蒼蒼，醖釀風威鑠夜缸。',64,'全唐诗/poet.song.152000.json','["勒回羲馭感蒼蒼，醖釀風威鑠夜缸。", "才喜篩寒初集霰，已憐灑急正聞窗。", "忘年有約將尋戴，好語先施合拜龐。", "不惜登臨矜共賞，萬妃正舞玉幡幢。"]'),
('04b437a6-5fb9-44b4-9a07-457edf0731d2','次韻謝傅公謀賀雪','許及之','宋','宋诗','song-poetry','','[]','寒入冰絲響玉琴，燎爐宿火費添薰。',64,'全唐诗/poet.song.152000.json','["寒入冰絲響玉琴，燎爐宿火費添薰。", "夢驚窗眼疑留月，起看簷牙有墮雲。", "三白預知開歲稔，一杯聊敢破朝醺。", "踵門佳士欣相顧，袖出名章過所聞。"]'),
('de256084-0ebb-440f-b5cd-aa4b62661c2e','喜雪  其一','許及之','宋','宋诗','song-poetry','','[]','靜聽微雨落乾聲，曉見平簷粉似勻。',64,'全唐诗/poet.song.152000.json','["靜聽微雨落乾聲，曉見平簷粉似勻。", "去歲鴛鴦何苦熱，今朝鷗鷺太無塵。", "眼空色界聊矜富，酒極詩豪自覺神。", "踏碎瓊瑶無過棹，虛教新釀熟經旬。"]'),
('e7379134-1b1d-4dfe-b652-0bae9e190488','喜雪  其二','許及之','宋','宋诗','song-poetry','','[]','擁火觀書硯不冰，梅將雪訪有交情。',64,'全唐诗/poet.song.152000.json','["擁火觀書硯不冰，梅將雪訪有交情。", "一寒依倚回春谷，三白牽連不夜城。", "玉燭試於調鼎見，金穰安待剪幡迎。", "代耕無補妨賢甚，歸去容成小築成。"]'),
('04834979-8e5a-4c79-9a88-b2172532799a','立春前一日喜雪','許及之','宋','宋诗','song-poetry','','[]','司寒顓帝職云虔，肯許勾神撓雪權。',64,'全唐诗/poet.song.152000.json','["司寒顓帝職云虔，肯許勾神撓雪權。", "雙勝迎春猶卜夜，六花殿臘已書年。", "太陽更不虧元日，聖德由來格上天。", "慚愧小臣無補報，巴歌敢共郢爭妍。"]'),
('a82ba889-b100-4af4-a16c-3d658e605cb2','和袁同年接伴謁洪澤鎮龍祠韻','許及之','宋','宋诗','song-poetry','','[]','鬼神爲德著冥冥，不在牲牷只在誠。',64,'全唐诗/poet.song.152000.json','["鬼神爲德著冥冥，不在牲牷只在誠。", "護客往來今九度，感神昭假等三成。", "長安妥帖平於席，畫舫夷猶穩作程。", "應鑒微衷有孤憤，中原却隔泗州城。"]'),
('0682e5da-98b4-45dd-9791-553a96094362','觀新堡寨因登平山堂次接伴袁同年韻','許及之','宋','宋诗','song-poetry','','[]','換得玻瓈千頃湖，醉翁遺勝在江都。',64,'全唐诗/poet.song.152000.json','["換得玻瓈千頃湖，醉翁遺勝在江都。", "登臨山色依然在，拂略秋容澹欲無。", "新堡似雲屯戍久，舊臣何日策勳殊。", "王人按壘非尋勝，歸報前遊有遠圖。"]'),
('24bcb682-b3c6-41e8-940e-be4694ecfc41','訪舊隠','許及之','宋','宋诗','song-poetry','','[]','自知樗櫟任天材，閒愛浮萍靜愛苔。',64,'全唐诗/poet.song.152000.json','["自知樗櫟任天材，閒愛浮萍靜愛苔。", "歸有幽棲鄰佛住，時因佳客下山來。", "青雲乳酒聊傾尾，白雪形鹽旋摘梅。", "有月有琴君勿去，百年懷抱待君開。"]'),
('4e110562-e1dd-470c-84dc-338bf9c566b4','買山石航海有懷故園','許及之','宋','宋诗','song-poetry','','[]','它山移却伴疎篁，磊砢堅於百鍊剛。',64,'全唐诗/poet.song.152000.json','["它山移却伴疎篁，磊砢堅於百鍊剛。", "劚地尚餘蒼蘚篆，傍欄偏映紫荷囊。", "濕雲矯矯飛還凝，煇鳳亭亭舞復翔。", "竹弟石兄應共語，故園那得負風光。"]'),
('4f2108d4-f691-477c-9b67-a021c61cabbb','益老過靈巖看築塘因慰藉小隠索詩','許及之','宋','宋诗','song-poetry','','[]','孤雲一片自由身，古剎隨緣有夙因。',64,'全唐诗/poet.song.152000.json','["孤雲一片自由身，古剎隨緣有夙因。", "小隠未容蠶作繭，靈巖要看海揚塵。", "築塘衣鉢時時唱，信筆詩篇句句新。", "晝繡不須歸相里，聞師自是鴈山人。"]'),
('76b18c58-cd98-468b-b3c6-fb2bef918ce3','題州宅安航','許及之','宋','宋诗','song-poetry','','[]','以涉名齋敢自遑，朅來何事得安航。',64,'全唐诗/poet.song.152000.json','["以涉名齋敢自遑，朅來何事得安航。", "極知平地風波少，得似閒居氣味長。", "旋了兒癡便退食，聊爲僧坐靜焚香。", "君恩未報空華髮，孤嶼扁舟憶故鄉。"]'),
('b728a0f6-8acc-4df8-9545-16a433402cfe','潘德久將出疆之前三日移居作詩奉邀','許及之','宋','宋诗','song-poetry','','[]','久住京華似故鄉，遷居又復一番忙。',64,'全唐诗/poet.song.152000.json','["久住京華似故鄉，遷居又復一番忙。", "此非子坐爭懸榻，何以家爲便出疆。", "屋下已聽湖水過，樓頭不奈柳梢黄。", "今朝元巳佳天氣，試撥忙來共一觴。"]'),
('94ad54da-107a-47e5-98ef-aee025b573de','喜聞轉庵新結暖閣因賦','許及之','宋','宋诗','song-poetry','','[]','老來百事一無能，寒燠隨宜護寢興。',64,'全唐诗/poet.song.152000.json','["老來百事一無能，寒燠隨宜護寢興。", "小院回廊慵勃窣，圍爐暖閣便瞢騰。", "向陽挾策明開牖，隠几聽歌厚覆憑。", "聞道轉庵新結束，宛同臭味我良朋。"]'),
('51f39c50-b7f6-46bc-b629-849e681f2422','次韻轉庵步城南有卜居依壑意乃古巽吉庵之旁','許及之','宋','宋诗','song-poetry','','[]','出郊緩步當乘流，依壑幽尋少餞秋。',64,'全唐诗/poet.song.152000.json','["出郊緩步當乘流，依壑幽尋少餞秋。", "水過斗門知浦口，庵當巽地見峯頭。", "賞心便擬爲鄰卜，志喜姑先著句留。", "祇恐據鞍方矍鑠，未容此處就菟裘。"]'),
('af81fd8a-4280-4e3a-9135-ef9190134ca8','適庵','許及之','宋','宋诗','song-poetry','','[]','庵居奚以適爲名，癢處能爬是適情。',64,'全唐诗/poet.song.152000.json','["庵居奚以適爲名，癢處能爬是適情。", "社後有誰留去燕，春來何處不遷鶑。", "物情雅與閒相會，酒興酣時句自成。", "要識適庵同一切，客來不用舉深觥。"]'),
('6e319dcc-f8eb-44c9-8130-7d3a1d799f18','浄光丈室開小窗頗得江山之勝次璧老壁間韻','許及之','宋','宋诗','song-poetry','','[]','車馬憧憧走皂臺，面皮三寸積黄埃。',64,'全唐诗/poet.song.152000.json','["車馬憧憧走皂臺，面皮三寸積黄埃。", "禪房永日窗開闔，天際孤帆潮往回。", "二月風光供遠眺，十年羈旅愜重來。", "現前一宿圓成案，懶向胡僧問劫灰。"]'),
('16d74a0c-8a72-4e2c-9bbf-3827144b24ea','益老于雁山築庵名曰來風小隠來求詩且約相見  其一','許及之','宋','宋诗','song-poetry','','[]','師住靈巖飽看山，結茅猶欲老山間。',64,'全唐诗/poet.song.152000.json','["師住靈巖飽看山，結茅猶欲老山間。", "懸知客路紅塵軟，輸與禪房白日閒。", "蔬筍忘來詩格瘦，楓梧落後鬢絲斑。", "煩師護取龍湫水，待覓涓涓洗我頑。"]'),
('76ca8cd2-12a6-4f2c-9f9f-a887c9e7d046','益老于雁山築庵名曰來風小隠來求詩且約相見  其二','許及之','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','未終棋局爛腰柯，繫日長繩竟若何。',64,'全唐诗/poet.song.152000.json','["未終棋局爛腰柯，繫日長繩竟若何。", "報國有心祇皎潔，效忠無力恐蹉跎。", "秋懷擬向樽前遣，歸夢偏於馬上多。", "八月錢塘江上景，可能作意莫相過。"]'),
('0dd483b2-5267-4150-8a48-711ff5c69646','被旨祈禱數至天竺珪僧錄求白雲堂詩爲賦唐律一首','許及之','宋','宋诗','song-poetry','','[]','白雲峯下白雲堂，堂上高人一辦香。',64,'全唐诗/poet.song.152000.json','["白雲峯下白雲堂，堂上高人一辦香。", "繞殿持經山四合，繚牆行道木千章。", "衆生未免嬰時苦，大士寧能與世忘。", "祈雨祈晴來復去，此身却似白雲忙。"]'),
('81eaee81-3f7c-4883-9a2a-7bcdcc905383','邀德久兄靈芝納凉','許及之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','曾許西湖三百首，官身其奈苦相妨。',64,'全唐诗/poet.song.152000.json','["曾許西湖三百首，官身其奈苦相妨。", "追陪歲月多遺策，零落風煙有斷章。", "人道拾遺無好句，天教老監學清狂。", "且邀海內忘形友，領攬招提半日凉。"]'),
('206f7bb9-a748-4098-b52c-1792c0da97be','高峰寺','許及之','宋','宋诗','song-poetry','','[]','四面峯巒玉斲成，團欒真是梵王城。',64,'全唐诗/poet.song.152000.json','["四面峯巒玉斲成，團欒真是梵王城。", "名山勝絕茲爲冠，墨客冥搜遠作程。", "清酌獻茶修薄供，攝心歸敬誓餘生。", "全家飽煖君恩重，佛日光中祝聖明。"]'),
('85a8c0f8-8248-4883-bbe3-29ec2db3af62','袁性之自號爲湖山遺老曩和予北征絕句因與其族人赴舉復見訪坐間求書湖山隠居扁榜因爲著語','許及之','宋','宋诗','song-poetry','','[]','湖山本爲吾儕設，家世今爲隠者居。',64,'全唐诗/poet.song.152000.json','["湖山本爲吾儕設，家世今爲隠者居。", "歲稔石田猶可飽，詩成霜葉正堪書。", "因觀後進鏖勍敵，肯訪閒人款敝廬。", "醉覓扁顔吾敢靳，和篇曾枉百硨磲。"]'),
('38011451-340e-4682-bda0-54aa29029e8e','隠居即事有懷潮州三首  其一','許及之','宋','宋诗','song-poetry','','[]','屋後如屏擁碧岑，愛山疊石尚同心。',64,'全唐诗/poet.song.152000.json','["屋後如屏擁碧岑，愛山疊石尚同心。", "肩輿不解勞人力，振策惟便助足音。", "未擲裹巾行曉色，不眠乘月坐秋陰。", "幽憂莫道都無景，十月移春要滿林。"]'),
('7f922a84-a948-4663-af0d-7a73d924574e','隠居即事有懷潮州三首  其二','許及之','宋','宋诗','song-poetry','','[]','載花航石自都城，慚愧波神每不驚。',64,'全唐诗/poet.song.152000.json','["載花航石自都城，慚愧波神每不驚。", "官職有何消得處，園池亦只信緣成。", "賞心擇勝難扁榜，信口哦詩莫主名。", "無奈新開城上路，江山如畫總相迎。"]'),
('af15714e-916a-4b84-bfc0-4932e99f7fb6','隠居即事有懷潮州三首  其三','許及之','宋','宋诗','song-poetry','','[]','忘形海內鮑潮州，遲次天教得共遊。',64,'全唐诗/poet.song.152000.json','["忘形海內鮑潮州，遲次天教得共遊。", "行李未還長問訊，扶藜纔過許賡酬。", "湖光催我頻携酒，花影何時傍結樓。", "昨夜滿庭秋月色，一年無此亦知不。"]'),
('463c1024-5861-42e9-9305-d56ff964e4fc','爲季和弟作溪堂扁榜賦唐律一首紀實','許及之','宋','宋诗','song-poetry','','[]','鴒原分派住松山，溪繞山圍屋數間。',64,'全唐诗/poet.song.152000.json','["鴒原分派住松山，溪繞山圍屋數間。", "今少蓬成今宅相，舊將軍寫舊堂顔。", "移來城市真堪貴，纔混囂塵便等閒。", "教子教孫風月夜，琴書聲裏水潺潺。"]'),
('23a5d1b2-3387-4c73-b916-dfcc77366e2d','清卿求作混碧樓額因賦唐律  其一','許及之','宋','宋诗','song-poetry','','[]','三十聲名晚合酬，前銜久自是潮州。',64,'全唐诗/poet.song.152000.json','["三十聲名晚合酬，前銜久自是潮州。", "尚須漢吏二千石，聊卧元龍百尺樓。", "混碧繆書波畫去，醉紅憶爲海棠留。", "從今只願摶扶上，還許澄鮮守舍不。"]'),
('6a5edf2f-37c6-47d5-8dff-fd27a09dd9da','清卿求作混碧樓額因賦唐律  其二','許及之','宋','宋诗','song-poetry','','[]','欵乃聲中自答酬，湖山迥闊冠吾州。',64,'全唐诗/poet.song.152000.json','["欵乃聲中自答酬，湖山迥闊冠吾州。", "際天野色青環坐，照水嵐光翠擁樓。", "蓮浦渺瀰無路到，松亭依約有船留。", "澄鮮近市翻堪恨，混碧能容數過不。"]'),
('57b81220-3a59-49a0-9e01-b37557bd7f63','袁起巖侍郎采予無盡意詩語以一段奇爲凈相別室扁榜有詩次韻','許及之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一段奇中無盡意，西湖風月契三生。',64,'全唐诗/poet.song.152000.json','["一段奇中無盡意，西湖風月契三生。", "只今扁榜成佳話，它日尋詩有舊盟。", "得失鷄蟲何日了，去來鳬鴈逐時更。", "癡兒尚欠梅花句，已擬長歌出塞行。"]'),
('ccfca2fe-9b0c-403e-9919-da13feb36169','高秀才紳十年前有同邸之舊以劍名堂求詩','許及之','宋','宋诗','song-poetry','','[]','沙河燈火闇殘更，客舍猶聞諷誦聲。',64,'全唐诗/poet.song.152000.json','["沙河燈火闇殘更，客舍猶聞諷誦聲。", "科舉累人須要了，詞章似子豈無成。", "勳名合是男兒事，通塞能忘造化情。", "莫向斗牛占氣采，夜深只願少微明。"]'),
('e04df418-4b85-4f08-b062-73652c597df7','范湘潭岸花樓','許及之','宋','宋诗','song-poetry','','[]','杜若青青湘水深，長官爲政見瑶琴。',64,'全唐诗/poet.song.152000.json','["杜若青青湘水深，長官爲政見瑶琴。", "飛花幾度春來去，行客自如人古今。", "天池百年供旅寓，江山一色費登臨。", "楚峯驛伴湘中館，更有高樓待賞心。"]'),
('ed315a83-e8bb-4036-adfa-a4cf0f91efcf','侶鷗亭','許及之','宋','宋诗','song-poetry','','[]','世態浮雲轉首非，孰於靜處見天機。',64,'全唐诗/poet.song.152000.json','["世態浮雲轉首非，孰於靜處見天機。", "愛憎隨俗烏能好，爵祿無心牛自肥。", "此樂尚憂兒輩覺，斯人休祝我公歸。", "公如畧起功名念，鷗鳥驚人已浪飛。"]'),
('8b48aed1-6a48-467a-b050-b7af098dd064','題富覽亭','許及之','宋','宋诗','song-poetry','','[]','萬峯如鶩萬波同，擘浪雙鼇躍勢雄。',64,'全唐诗/poet.song.152000.json','["萬峯如鶩萬波同，擘浪雙鼇躍勢雄。", "山過江來垂斗柄，水朝宗去渙文風。", "家家洙泗絃歌裏，處處蓬瀛圖畫中。", "莫笑先生徒壁立，一番登覽興無窮。"]'),
('fe931741-cae2-4ad0-86f2-357646e034b6','登憶謝亭併呈質弟','許及之','宋','宋诗','song-poetry','','[]','爭不遊山憶謝公，亭成孤嶼恰當中。',64,'全唐诗/poet.song.152000.json','["爭不遊山憶謝公，亭成孤嶼恰當中。", "山低山仰今朝異，潮落潮生自古同。", "幾欲弄舟移白日，何當把釣待秋風。", "惠連幸自還鄉里，獨恨池塘句不工。"]'),
('0f2ece2b-2525-450e-8379-4c7f1f83ce99','題春風亭','許及之','宋','宋诗','song-poetry','','[]','亭成秋日榜春風，歲稔時和荷化工。',64,'全唐诗/poet.song.152000.json','["亭成秋日榜春風，歲稔時和荷化工。", "佳事感傷多白髮，壯懷突兀祇孤忠。", "漢興即有中天運，吏惰元無闢地功。", "只把春風宣聖化，物華都在發生中。"]'),
('ccfb7004-5cd6-48f9-8173-17c335d51cd3','題外祖母夫人李氏墓陟屺亭','許及之','宋','宋诗','song-poetry','','[]','陟屺哀哀八十親，渭陽念母我傷情。',64,'全唐诗/poet.song.152000.json','["陟屺哀哀八十親，渭陽念母我傷情。", "等爲孝子終身慕，最慘嬰兒半路聲。", "已把山光占塾教，底須宅相寫亭名。", "登亭更望芙蓉頂，吹棘風前淚併傾。"]'),
('328bc775-25ff-487b-9954-d0fb68dd227d','春晚登鈐岡','許及之','宋','宋诗','song-poetry','','[]','簿書拋罷一登臨，恰有黄鸝送好音。',64,'全唐诗/poet.song.152000.json','["簿書拋罷一登臨，恰有黄鸝送好音。", "溪漲未消知雨近，林疎頓密見春深。", "詩源久廢如枯井，宦况多磨似鍊金。", "手種故圍三四竹，新梢拂拂想成陰。"]'),
('23c2641e-364c-45b7-9373-b319f58dc544','游金山寺','許及之','宋','宋诗','song-poetry','','[]','何年浮玉奠中川，潮去潮來故屹然。',64,'全唐诗/poet.song.152000.json','["何年浮玉奠中川，潮去潮來故屹然。", "世事只隨波上過，佛身元向定中圓。", "妙高得月天無際，雄跨看雲雨带烟。", "孤嶼扁舟無活計，又拏楊子渡頭船。"]'),
('244eef64-180c-4fb3-9f35-48d16e7776ab','登江山偉觀','許及之','宋','宋诗','song-poetry','','[]','江山如抱畫難加，偉觀標名似太誇。',64,'全唐诗/poet.song.152000.json','["江山如抱畫難加，偉觀標名似太誇。", "千古雲烟無盡藏，百年登覽足生涯。", "詩情與客來天際，潮汛邀人上斗槎。", "自是皇恩聊許借，兒童莫便認吾家。"]'),
('b72ccd5f-cf07-4a49-a43e-64acdd6ca908','題石乳洞','許及之','宋','宋诗','song-poetry','','[]','山前老石碧巑岏，山後縈紆洞府寬。',64,'全唐诗/poet.song.152000.json','["山前老石碧巑岏，山後縈紆洞府寬。", "妙處通行隨步武，到頭平坦上團欒。", "寶鍾池秘金爲奏，甘井天成玉作欄。", "古怪洪陽清石乳，平章留與後人看。"]'),
('c4c8a775-1fb6-4e4c-83f9-69370cccf59c','游仙都','許及之','宋','宋诗','song-poetry','','[]','我來古括經行熟，欲到仙都有底難。',64,'全唐诗/poet.song.152000.json','["我來古括經行熟，欲到仙都有底難。", "漫道蓬萊環弱水，始知方丈近三韓。", "千山開闔神仙迥，一柱岧嶢宇宙寒。", "信有真人足官府，不妨容我暫鞭鸞。"]'),
('3f9a80bd-488e-4e7b-a5be-87ab2c37f87c','初入雁山見雙峰','許及之','宋','宋诗','song-poetry','','[]','鐘鼎山林昔罕兼，久污清貫大傷廉。',64,'全唐诗/poet.song.152000.json','["鐘鼎山林昔罕兼，久污清貫大傷廉。", "移文謝客顔情厚，彈劾歸耕喜屬饜。", "纔下盤山爲邑里，已排勝境入詩籤。", "年來百慮消磨盡，只有雙峰不退尖。"]'),
('e3652129-b053-4482-b809-b45bb3f3254f','再遊雁蕩觀雙峰','許及之','宋','宋诗','song-poetry','','[]','不到雙峰一紀年，夢隨清磬上高圓。',64,'全唐诗/poet.song.152000.json','["不到雙峰一紀年，夢隨清磬上高圓。", "重來慣識羊腸路，兀坐慵談兔角禪。", "欲剗舊題無好語，羞將華髮照清泉。", "男兒問學全無用，愧爾耕夫墾石田。"]'),
('6b0d131f-1c77-48fc-9e40-d9835c753f3c','遊南明山','許及之','宋','宋诗','song-poetry','','[]','路上崔嵬斷復連，危亭却立虎溪邊。',64,'全唐诗/poet.song.152000.json','["路上崔嵬斷復連，危亭却立虎溪邊。", "石梁架厂疑無地，巖竇梯雲欲近天。", "客子詩情專物色，老僧禪悅解行纏。", "亦知太與塵凡隔，時遣鐘聲落市廛。"]'),
('a80227bd-2a72-41ee-b3b5-b099b6757ee7','下四十九盤','許及之','宋','宋诗','song-poetry','','[]','了知四十九年非，七七盤中共一機。',64,'全唐诗/poet.song.152000.json','["了知四十九年非，七七盤中共一機。", "世路險夷行處是，身名榮耀眼前稀。", "此生待足何時足，平日思歸今得歸。", "厚祿故人如問訊，爲言留得故山薇。"]'),
('e26897cd-08a8-4cb1-858c-e2585359f7a1','春園','許及之','宋','宋诗','song-poetry','','[]','用世無功孰取材，誅茅作計剔荒苔。',64,'全唐诗/poet.song.152000.json','["用世無功孰取材，誅茅作計剔荒苔。", "花隨淺綠流春去，山擁新青入坐來。", "寬闢軒窗便過夏，高藏書畫待經梅。", "菊苗先晚丁寧種，更要秋光次第開。"]'),
('b437a134-776c-42d3-9db4-0dfe5f309eb0','喜子儀侍郎同遊','許及之','宋','宋诗','song-poetry','','[]','擬訪南山自北山，長隄信馬只如閒。',64,'全唐诗/poet.song.152000.json','["擬訪南山自北山，長隄信馬只如閒。", "畫船瞥見矜紅粉，紫燕驚飛透白鷳。", "三過名園成選勝，再臨高閣似知還。", "茲遊不負花時節，寡和陽春更許攀。"]'),
('060e049d-1276-4142-981e-df3a12482f78','題洪陽洞','許及之','宋','宋诗','song-poetry','','[]','劃開靈怪幾千年，傳與洪陽二老仙。',64,'全唐诗/poet.song.152000.json','["劃開靈怪幾千年，傳與洪陽二老仙。", "石室盡頭真境秘，天窗明處葆光圓。", "乳泉煖滴燒丹井，芝徑畦分種玉田。", "不是到來須束火，故應名勝限囂廛。"]'),
('969e3c3a-817d-47fe-b2b7-8d4b07ddb5bc','聞轉庵遊西湖奉寄','許及之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','馬上春光過若馳，不須紀歷校花時。',64,'全唐诗/poet.song.152000.json','["馬上春光過若馳，不須紀歷校花時。", "青於前日長街柳，白似去年雙鬢絲。", "强學後生須藉酒，苦邀同社索題詩。", "朝回要便西湖去，輸與安仁尚黑髭。"]'),
('5a384031-7264-44f6-93be-ef76d146cb20','酬常之換韻和江心寺詩','許及之','宋','宋诗','song-poetry','','[]','千峯屏繞浪環鋪，莫把金焦作對呼。',64,'全唐诗/poet.song.152000.json','["千峯屏繞浪環鋪，莫把金焦作對呼。", "絕境誰闚全體現，小亭人號媚川圖。", "市聲非遠塵難到，塔影雖雙嶼只孤。", "大似橘洲浮不去，嶽根元插赤沙湖。"]'),
('2d9eb73f-f594-4dbb-99d3-2764474820d7','再次常之換韻題江心寺詩','許及之','宋','宋诗','song-poetry','','[]','山川如畫鎮長鋪，每坐危亭謂笑呼。',64,'全唐诗/poet.song.152000.json','["山川如畫鎮長鋪，每坐危亭謂笑呼。", "大艑揚帆飛畧彴，巨鼇出水載浮圖。", "錦袍仙想前嶢古，飯顆神遊絕境孤。", "不是謝公親歷覽，相忘祇竟渺江湖。"]'),
('6e9032ff-daab-4be1-b1fc-a2a24314866a','媚川圖亭上觀江心寺','許及之','宋','宋诗','song-poetry','','[]','三山海上失雙峯，插作中川鎮水龍。',64,'全唐诗/poet.song.152000.json','["三山海上失雙峯，插作中川鎮水龍。", "高出赭垣尊御寢，長拖粉廡過僧筇。", "夜敲圖繞千燈磬，曉擊聲聞兩岸鍾。", "莫恨無緣隨展鉢，時來亭上足從容。"]'),
('e27f7bbd-5a34-4c83-8f85-8bb646e65224','某謬題媚川圖江心寺晚荷仲歸兄依韻寵和至再愈工勉酬厚意終慚辭費','許及之','宋','宋诗','song-poetry','','[]','孤亭面直海壇峯，真覩龍翔瑞應龍。',64,'全唐诗/poet.song.152000.json','["孤亭面直海壇峯，真覩龍翔瑞應龍。", "長羨僧行圖上境，不勞杯渡水邊筇。", "推移日月東西塔，透徹天淵昏曉鍾。", "妙處難將聲相見，吟摹終恐費形容。"]'),
('d03e35c5-8d8e-4739-9d93-3482b09851c9','酬翁常之和媚川圖上觀江心寺詩','許及之','宋','宋诗','song-poetry','','[]','江北屯雲翳列峯，江心靈雨走神龍。',64,'全唐诗/poet.song.152000.json','["江北屯雲翳列峯，江心靈雨走神龍。", "已拚阮子一生屐，更倚仙人九節筇。", "晻靄孤帆昏野渡，霏微兩塔濕疎鍾。", "何須小米模糊筆，潘令新詩足寫容。"]'),
('31b1d375-aead-455b-b0d4-dff71e8059e9','送吳待制安撫襄陽  其一','許及之','宋','宋诗','song-poetry','','[]','天借琳琅鎮上流，西風作意送行舟。',64,'全唐诗/poet.song.152000.json','["天借琳琅鎮上流，西風作意送行舟。", "去看峴首何因感，遥見長安却是愁。", "平昔勳名期带礪，向來談笑飽貔貅。", "輕裘少展籌邊畧，歸問君王覓酇侯。"]'),
('0a453980-925c-4ff4-b228-f137cddb2ae9','送吳待制安撫襄陽  其二','許及之','宋','宋诗','song-poetry','','[]','如君自是急難材，牛斗光芒未燭台。',64,'全唐诗/poet.song.152000.json','["如君自是急難材，牛斗光芒未燭台。", "何以家爲人咄咄，維其時矣詔來來。", "臨湖盡去封侯橘，度地先栽調鼎梅。", "惡語流傳真引玉，滿懷明月向人開。"]'),
('cf3f4190-92c9-42a1-80f7-f098e08f5c97','送何正言持節湖南','許及之','宋','宋诗','song-poetry','','[]','山莊寂寞信驚猿，鵷鷺行疎亦斷魂。',64,'全唐诗/poet.song.152000.json','["山莊寂寞信驚猿，鵷鷺行疎亦斷魂。", "持節過家天借便，引嫌得請帝疏恩。", "湘雲開處峰峰好，諫紙藏來字字溫。", "只恐夜深思賈傅，長沙寧久駐軺軒。"]'),
('68f57209-8433-4451-9e10-93d866146de6','送趙端明帥蜀','許及之','宋','宋诗','song-poetry','','[]','謀深無位可酬功，端殿几廷禮數同。',64,'全唐诗/poet.song.152000.json','["謀深無位可酬功，端殿几廷禮數同。", "盡以四川歸節制，重乘九折見精忠。", "平生清白天垂相，簡在登庸帝降衷。", "萬里橋頭莫言遠，恩波只在大江通。"]'),
('1351946a-9029-48b0-9884-1cf5415c1444','送鄒國遂武博知濠州二首  其一','許及之','宋','宋诗','song-poetry','','[]','長髯如㦸氣如虹，只欠吾曹抹額紅。',64,'全唐诗/poet.song.152000.json','["長髯如㦸氣如虹，只欠吾曹抹額紅。", "右序談兵瓴建水，上前論事殿生風。", "懇辭射策登賓閣，乞許分符立戰功。", "他日濠梁真得意，要看魚水得君同。"]'),
('7dd34b7e-6815-42a5-a87a-3088ca738dce','送鄒國遂武博知濠州二首  其二','許及之','宋','宋诗','song-poetry','','[]','孤嶼秋風憶釣蓑，因君理櫂起勞歌。',64,'全唐诗/poet.song.152000.json','["孤嶼秋風憶釣蓑，因君理櫂起勞歌。", "分留鄉思從茲始，報答君恩奈若何。", "陶令籬傍猶有菊，伯齡石上苦無禾。", "問言何補青蒲事，爲道新來白髮多。"]'),
('d9ef8920-871e-4a81-9b49-513b66e4a4c7','送毛監丞知漳州','許及之','宋','宋诗','song-poetry','','[]','參裨不解力吹噓，摻別何勞嘆索居。',64,'全唐诗/poet.song.152000.json','["參裨不解力吹噓，摻別何勞嘆索居。", "子去定爲慈父母，邦人應得樂田廬。", "臨漳從此無苛吏，嚴瀨曾聞治猾胥。", "暇日若親橫槊賦，爲言珍重百硨磲。"]'),
('ac7e3e2d-3785-4224-a26e-96188e94018a','送胡司諫同年赴湖北漕','許及之','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭青草碧相連，使節經行別有天。',64,'全唐诗/poet.song.152000.json','["洞庭青草碧相連，使節經行別有天。", "又輟諫官湖外去，要蘇民力未央前。", "一枝臘雪邊江驛，百丈春潮上水船。", "小駐軺軒私雨露，司存及早侍甘泉。"]'),
('7eb72063-07a5-4808-bdb8-a5281a6c14d3','送潘德久都幹爲賀生辰使屬','許及之','宋','宋诗','song-poetry','','[]','廼翁舊取燕山第，子恰從人去使燕。',64,'全唐诗/poet.song.152000.json','["廼翁舊取燕山第，子恰從人去使燕。", "孽子孤臣應有淚，祖功宗德本無邊。", "離離故國摇鞭影，耿耿新詩貯腹便。", "父老相逢勤勞苦，爲言咫尺中興年。"]'),
('616bdd68-8574-4f6a-8d4d-4ac809ce8753','送張子儀尚書鎮福州','許及之','宋','宋诗','song-poetry','','[]','暫違天陛星辰履，便上春風李郭船。',64,'全唐诗/poet.song.152000.json','["暫違天陛星辰履，便上春風李郭船。", "兩地逼人真勇退，三山去路儼登仙。", "循環花甲趨庭日，遺笏棠陰在鎮年。", "盛事相望已無匹，寶奎新賜更光前。"]'),
('acf9e258-d57f-449f-9603-625488708d0c','送直院樓尚書同年以閣學知婺州二首  其一','許及之','宋','宋诗','song-poetry','','[]','受敵詞章八面全，慶元書詔四方傳。',64,'全唐诗/poet.song.152000.json','["受敵詞章八面全，慶元書詔四方傳。", "星辰聽履聊紆步，筆墨論功即化權。", "將母願爲符竹計，投誠徑繳冕旒前。", "暫煩明月雙溪照，兩兩台星尺五天。"]'),
('794530af-3788-4675-89e0-8a6934a0fd3d','送直院樓尚書同年以閣學知婺州二首  其二','許及之','宋','宋诗','song-poetry','','[]','隆興最盛初元榜，當日曾推第一人。',64,'全唐诗/poet.song.152000.json','["隆興最盛初元榜，當日曾推第一人。", "出世經綸知幾佛，看君意度不無神。", "居然勇退非驚俗，行矣追隨亦爲親。", "只恐苦無明月句，經行難作隠侯賓。"]'),
('4be05375-f0c6-48b8-83fc-b0998840ceb6','送禹之皋之舅赴調二首  其一','許及之','宋','宋诗','song-poetry','','[]','我是次公門下客，登龍因許與乘龍。',64,'全唐诗/poet.song.152000.json','["我是次公門下客，登龍因許與乘龍。", "只今擊柝從關吏，漸可扶犁作老農。", "莫報黄壚埋白玉，滿看清廟列金鐘。", "二難自是從來譽，勉事功名定亢宗。"]'),
('d4adc753-4a8a-4f28-bf3b-fa4a5487a6bc','送禹之皋之舅赴調二首  其二','許及之','宋','宋诗','song-poetry','','[]','九年清夢落鳴珂，尊酒相逢奈樂何。',64,'全唐诗/poet.song.152000.json','["九年清夢落鳴珂，尊酒相逢奈樂何。", "但恨醉人成謬誤，莫嗔驚汝感摩挲。", "行裝忽指吳門道，別意今隨楚水波。", "若訪水僊逢處士，爲言新句苦無多。"]'),
('a0dccf8b-f5f6-4e98-8cc2-c1994208a723','用樓尚書韻餞同年曾寺丞守溫州','許及之','宋','宋诗','song-poetry','','[]','三十三年同日喜，憶曾書札問淮堧。',64,'全唐诗/poet.song.152000.json','["三十三年同日喜，憶曾書札問淮堧。", "造朝合究三千牘，出守聊違尺五天。", "官舍君應思繫馬，家山我亦念斜川。", "政成的有天官列，不擬攀轅擬執鞭。"]'),
('f43a77b7-ada4-4bc8-ae10-06640461fef6','送劉東玉提幹之官茂苑','許及之','宋','宋诗','song-poetry','','[]','共論隸古弄文漪，酌別寧忘載酒巵。',64,'全唐诗/poet.song.152000.json','["共論隸古弄文漪，酌別寧忘載酒巵。", "去去臺中攄婉畫，行行篋裏富新詩。", "向來閥閲多丹禁，豈有人門後白眉。", "九萬扶摇從此始，他年書劄問茅茨。"]'),
('9f9fe83d-45f5-41eb-8cf3-c670bbf2a84c','送石謙伯就許襄陽辟','許及之','宋','宋诗','song-poetry','','[]','襄陽耆舊流風在，幕府文書併省餘。',64,'全唐诗/poet.song.152000.json','["襄陽耆舊流風在，幕府文書併省餘。", "勿以脩塗愁泛宅，不妨勝處憩安輿。", "碑存峴首堪懷古，詩憶槎頭匪爲魚。", "萬里功名從此始，勉旃聲價百硨磲。"]'),
('1c6a9f6f-ec44-4966-909f-4a35f21bb4d9','送鄭仁叔宰長溪','許及之','宋','宋诗','song-poetry','','[]','清於道骨澹於僧，海內忘形得此朋。',64,'全唐诗/poet.song.152000.json','["清於道骨澹於僧，海內忘形得此朋。", "作縣只如詩思苦，能官已被薦書騰。", "下車搏虎真堪笑，入境無蝗定有稱。", "我亦孤愚諳此味，願言加飯履春冰。"]'),
('fdf4b002-ff65-4cf9-bad2-0f8ac494d83c','黄叔萬知縣以魯名齋求詩將赴公安併以爲餞','許及之','宋','宋诗','song-poetry','','[]','堂堂張也竟難爲，一唯工夫魯得之。',64,'全唐诗/poet.song.152000.json','["堂堂張也竟難爲，一唯工夫魯得之。", "得兔故應忘百慮，亡羊正爾失多歧。", "千林摇落青還在，孤月當空影自隨。", "昔日校官今作縣，魯齋行處即吾師。"]'),
('07b77009-420a-4d2c-a91c-b521c359505a','送王子大知縣','許及之','宋','宋诗','song-poetry','','[]','金閨通籍綰銅章，荔子黄時恰到鄉。',64,'全唐诗/poet.song.152000.json','["金閨通籍綰銅章，荔子黄時恰到鄉。", "僧夏相期塵外住，官朞將趣橐中裝。", "傾心棲棘仇香地，側耳鳴絃單父堂。", "說著江西如故里，南城春色勝河陽。"]'),
('9822f115-fdba-4bf3-ab79-76588b7d0dd7','送余伯益知縣','許及之','宋','宋诗','song-poetry','','[]','建章萬戶及千門，博物如君自不羣。',64,'全唐诗/poet.song.152000.json','["建章萬戶及千門，博物如君自不羣。", "入幕向來爭論薦，鳴琴此去定知聞。", "官惟作縣堪行志，閩獨於鹽害未分。", "剖竹乘軺同臭味，願求長策獻吾君。"]'),
('86344686-efbc-4a77-ac2c-ec311c199826','送鄭節卿赴新喻丞併呈李諫議','許及之','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','南漳撫字溢三年，當路文章喜薦賢。',64,'全唐诗/poet.song.152000.json','["南漳撫字溢三年，當路文章喜薦賢。", "鶴髮有親須祿養，鶚書無地足常員。", "爲丞盍過滕王閣，詣府欣依刺史天。", "諫議恩深曾一顧，煩君爲我道拳拳。"]'),
('84343259-78c0-4e92-b78e-735ca9f64843','送鄭廷玉教授之官邵武','許及之','宋','宋诗','song-poetry','','[]','太學聲名十五年，雞林副墨競流傳。',64,'全唐诗/poet.song.152000.json','["太學聲名十五年，雞林副墨競流傳。", "諸生定滿升堂履，獨冷何愁坐客氈。", "預恐上方催給劄，便應西笑去朝天。", "君王若問安邊策，上藥良醫有十全。"]'),
('67357c20-f62a-446a-80bd-427d5a14c268','沈架閣席上送沈教授之官邵陽二首  其一','許及之','宋','宋诗','song-poetry','','["\u8861\u5c71"]','祝融七十二峯尊，諸老相望古道存。',64,'全唐诗/poet.song.152000.json','["祝融七十二峯尊，諸老相望古道存。", "二邵人才元有種，三湘風物向曾論。", "先生此去行師說，弟子從今記善言。", "爲訪衡山戴監嶽，可能畧不傍華軒。"]'),
('abbf8038-def5-4f5f-ac7e-10c3f8dcd7d7','沈架閣席上送沈教授之官邵陽二首  其二','許及之','宋','宋诗','song-poetry','','[]','郡侯名字祖鞭先，郡倅風流世有傳。',64,'全唐诗/poet.song.152000.json','["郡侯名字祖鞭先，郡倅風流世有傳。", "更著廣文鐺脚坐，亦憐委吏鼎科年。", "江山莫道非吾土，官舍曾無有此賢。", "自是蓬萊山上客，枉教予作送行篇。"]'),
('f033cbe0-f692-4b83-b2c6-e8527c7378f9','送簡壽王主簿之官番禺','許及之','宋','宋诗','song-poetry','','[]','住久江西近物情，聞名雖舊蓋初傾。',64,'全唐诗/poet.song.152000.json','["住久江西近物情，聞名雖舊蓋初傾。", "未聽健論折髯喜，况有新詩出袖清。", "爲簿免從高士例，飲泉要改昔人名。", "爲言牧伯乘驄舊，愧爾傳家折檻聲。"]'),
('c93e87a4-6e71-452f-880f-f31d63d60418','次韻臨川傅簿經過道舊之什','許及之','宋','宋诗','song-poetry','','[]','傾蓋臨川卜再逢，歲華飄忽老秋風。',64,'全唐诗/poet.song.152000.json','["傾蓋臨川卜再逢，歲華飄忽老秋風。", "汗顔何補千人聚，過眼還驚萬馬空。", "今子所淹棲棘地，曩余曾掌采芹宮。", "種松已長煩公問，梁棟如今中未中。"]'),
('ca4a74e5-5a3d-47ef-8e98-62a60e7a3991','送鮑清卿運幹調官還里二首  其一','許及之','宋','宋诗','song-poetry','','[]','筆端有印印金泥，榜榜名高米樣齊。',64,'全唐诗/poet.song.152000.json','["筆端有印印金泥，榜榜名高米樣齊。", "兩郡漫遊官似水，七階懶覓薦爲梯。", "登瀛已近帆驚轉，入幕雖卑首願低。", "舉士引嫌堪自愧，眼看湖海放鳧鷖。"]'),
('9e16240a-7c94-4dad-895c-f3fb64e870fc','送鮑清卿運幹調官還里二首  其二','許及之','宋','宋诗','song-poetry','','[]','家住城南水竹村，羨君月榭與風軒。',64,'全唐诗/poet.song.152000.json','["家住城南水竹村，羨君月榭與風軒。", "頭顱已料書生骨，言語難酬明主恩。", "何日致還歸里社，也教依樣買山村。", "彈邊求炙君憐我，許種名葩寄後園。"]'),
('6984b0f2-8bd4-47e5-a7c2-ff60d00b5b9b','送范南宮守彭歸蜀','許及之','宋','宋诗','song-poetry','','[]','起草南宮著作庭，歷階亦合侍承明。',64,'全唐诗/poet.song.152000.json','["起草南宮著作庭，歷階亦合侍承明。", "乞身只擬分符去，持節何妨衣錦行。", "道在不孤知己舊，才難偏愴語離情。", "極知便下思賢詔，其奈巴江白髮生。"]'),
('31c4efc5-d72d-46cb-b551-7fe5b53ac8f4','送黄元章秘書還餘杭待次荆門','許及之','宋','宋诗','song-poetry','','[]','蓬萊雲色正飛浮，猛乞分符向玉州。',64,'全唐诗/poet.song.152000.json','["蓬萊雲色正飛浮，猛乞分符向玉州。", "抵鵲信嫌三獻辱，如虹肯要萬金酬。", "勳名不朽山爲礪，軒冕隨緣芥作舟。", "却憾渥漥求汗血，不如天廄出驊騮。"]'),
('b767dee3-d971-4b5f-aa7e-e9ce9c66c599','送鄭節推勝棄職歸省','許及之','宋','宋诗','song-poetry','','[]','慷慨中原泣夜闌，一門忠孝只南冠。',64,'全唐诗/poet.song.152000.json','["慷慨中原泣夜闌，一門忠孝只南冠。", "來歸九死賒猶易，就養一官輕底難。", "幕府禮羅留莫住，清時長鋏惜休彈。", "男兒富貴尋常事，要取功名與世看。"]'),
('3251d9c6-2bbf-4dc8-87f1-88fb28296772','送鄭南秀解秩東歸','許及之','宋','宋诗','song-poetry','','[]','小麥茸茸短覆泥，如何熟得濟民饑。',64,'全唐诗/poet.song.152000.json','["小麥茸茸短覆泥，如何熟得濟民饑。", "青黄未接我狼顧，黑白既分君解龜。", "已拜一言真苦口，極知三折是良醫。", "從今洗眼看華要，書札無忘慰夢思。"]'),
('5d7243bd-fe0a-4001-bc8f-9aa0c20a69f1','送穀仲歸謙謝以詩次韻奉酬','許及之','宋','宋诗','song-poetry','','[]','一樂長存抵萬金，百年誰肯放愁侵。',64,'全唐诗/poet.song.152000.json','["一樂長存抵萬金，百年誰肯放愁侵。", "飯蔬飲水真吾事，懷寶迷邦豈本心。", "桑戶琴歌奚此極，孔門絃誦有遺音。", "新詩當暑時時至，每讀清風自滿襟。"]'),
('38b6fe9d-2cf7-486b-a2a4-de788a9868df','送解省元赴南宮','許及之','宋','宋诗','song-poetry','','[]','過庭有子即同登，學圃承家豈足稱。',64,'全唐诗/poet.song.152000.json','["過庭有子即同登，學圃承家豈足稱。", "刻畫無鹽容更醜，寵光蕙草句全勝。", "名場自此一投足，宦路不須三折肱。", "累月笞兒吾豈敢，短檠猶可課秋燈。"]'),
('3259e63f-5d03-4697-a7a4-73407ef082fd','送林定國赴秋試','許及之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','讀却床頭滿架書，時文元不費工夫。',64,'全唐诗/poet.song.152000.json','["讀却床頭滿架書，時文元不費工夫。", "向來點額關奇數，今日焚舟合壯圖。", "去去秋風趨北闕，行行春色滿西湖。", "癡兒未了書生事，珍重青衫報國軀。"]'),
('aa4576e2-e12a-4a93-9d2a-4221b2c71088','送劉守之上舍赴試','許及之','宋','宋诗','song-poetry','','[]','廼翁壯譽動賢關，晚把州麾苦要閒。',64,'全唐诗/poet.song.152000.json','["廼翁壯譽動賢關，晚把州麾苦要閒。", "細字尚陪燈火課，淡書端要姓名攀。", "扶摇穩泛魚三級，文采曾闚豹一斑。", "舍弟若爲同日喜，兩家親老想開顔。"]'),
('b472bda4-74c4-4a2b-8f45-188e8bd131ca','次韻餞振之之行','許及之','宋','宋诗','song-poetry','','[]','半生經吏競分陰，奏牘三千幾汗青。',64,'全唐诗/poet.song.152000.json','["半生經吏競分陰，奏牘三千幾汗青。", "技到屠龍從俗笑，志存流水有人聽。", "故園勳業千株橘，世路生涯一草亭。", "却笑劉商長得醉，爲無管屬愛浮萍。"]'),
('abb390a3-450d-4a4f-b272-e72adf7e9e70','送安福劉秀才謀卿仍簡分宜傅公謀','許及之','宋','宋诗','song-poetry','','[]','昨夜西風入楚扉，登臨遊子倦將歸。',64,'全唐诗/poet.song.152000.json','["昨夜西風入楚扉，登臨遊子倦將歸。", "璧廱未頓新書笥，錦里還尋舊釣磯。", "平世勳名賒馬革，男兒貧賤且牛衣。", "傅巖詞客如相問，說是今非昨更非。"]'),
('bda1d179-8881-40b5-bd1b-a32f6a2b0e76','送德友之長沙章貢併懷薛葉二兄','許及之','宋','宋诗','song-poetry','','[]','篇章足可慕淵明，其奈田無二頃耕。',64,'全唐诗/poet.song.152000.json','["篇章足可慕淵明，其奈田無二頃耕。", "甥館久居誰厭汝，客塗遠問我憐生。", "湘山物色留新句，使節綈袍有故情。", "併語鬰孤東道主，春風吹夢到容成。"]'),
('654ba3f6-36e2-4025-afce-839473b2b52a','送陳西老西上併簡張功甫','許及之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','二月春光韻管絃，琴書獨上館頭船。',64,'全唐诗/poet.song.152000.json','["二月春光韻管絃，琴書獨上館頭船。", "篋中未有西湖句，闕下曾傳樂府篇。", "名勝難逢分手易，游從雖晚服膺先。", "有如尚待金門詔，須訪南湖桂隠僊。"]'),
('e3444135-864a-4bd2-92de-fa8445da3083','中川席上送陳同甫','許及之','宋','宋诗','song-poetry','','[]','眼底男兒隘六區，似君豪氣有誰如。',64,'全唐诗/poet.song.152000.json','["眼底男兒隘六區，似君豪氣有誰如。", "中原赤子頭今白，天下蒼生力未紓。", "北闕有書流涕上，西山無地带經鋤。", "共談世事何時了，勸子加餐返故廬。"]'),
('7fd7d148-fdc0-46fe-9620-66f661d54e50','送俊老再住惠因','許及之','宋','宋诗','song-poetry','','[]','天台自是金仙窟，而况師曾住惠因。',64,'全唐诗/poet.song.152000.json','["天台自是金仙窟，而况師曾住惠因。", "祖令全提餘作畧，舊營重按想精神。", "絕憐老宿參辰象，何限名藍甲乙人。", "若遇毒龍師攝取，經行杯渡熟知津。"]'),
('cd622ffc-072f-4833-a743-8b7ed75147a3','送清監寺往平陽化緣清乃王詹事女','許及之','宋','宋诗','song-poetry','','[]','詹事家中靈照女，圓月會下祖師禪。',64,'全唐诗/poet.song.152000.json','["詹事家中靈照女，圓月會下祖師禪。", "一條見地如絲直，百架脩廊尚結緣。", "飛錫先從坳裏去，擲盃聊當渡頭船。", "更於何處求真佛，說似檀那領現前。"]'),
('7f92fe7e-cd08-46c3-a6cd-fc2e618aaf7f','喜德久從人使北來歸','許及之','宋','宋诗','song-poetry','','[]','詩翁萬里恰歸來，滌面那無一點埃。',64,'全唐诗/poet.song.152000.json','["詩翁萬里恰歸來，滌面那無一點埃。", "生馬諳騎便武事，故京熟覽動詩才。", "別來我已成炊夢，此去君應悟劫灰。", "見說北庭猶假息，可無尊酒沃崔嵬。"]'),
('701c96f5-1257-4a81-985a-714b90056a00','和袁同年接伴賡從客陸成文韻','許及之','宋','宋诗','song-poetry','','[]','鴈塔題名不記年，相從淮海喜跫然。',64,'全唐诗/poet.song.152000.json','["鴈塔題名不記年，相從淮海喜跫然。", "了知鵬鷃懸微分，祇覺夔蚿有故憐。", "共泛仙舟凌浩渺，賡吟醉墨墮芳鮮。", "少游陳迹無尋處，小五湖中水拍天。"]'),
('494dcdd0-765e-4b70-abd4-95fad626b174','和袁同年接伴賡從客霍希文過楚州韻','許及之','宋','宋诗','song-poetry','','[]','一水分流西復東，畫船隨水去匆匆。',64,'全唐诗/poet.song.152000.json','["一水分流西復東，畫船隨水去匆匆。", "晚風鼓角增悲壯，高壘營屯足長雄。", "糧道已無清口應，舟師會把朔庭空。", "眼中方畧全圖在，未肯輕將屬畫工。"]'),
('21969970-593a-4dce-bc52-4e822346b8da','次韻袁同年回程見示','許及之','宋','宋诗','song-poetry','','[]','秋風日日動詩情，人與詩篇一樣清。',64,'全唐诗/poet.song.152000.json','["秋風日日動詩情，人與詩篇一樣清。", "歸去星辰添秀潤，經行草木倍精明。", "河山未閡功名志，歲月徒催鬢髮生。", "送客微言何足錄，便將佳句榻前呈。"]'),
('f3737cbf-35fe-4f47-a674-800105a02000','吳門次韻頤剛嚴陵留別過新安','許及之','宋','宋诗','song-poetry','','[]','功名破甑等虛空，身世隨緣邴曼容。',64,'全唐诗/poet.song.152000.json','["功名破甑等虛空，身世隨緣邴曼容。", "行色過於秋澹薄，離情恰似酒醇濃。", "想君時看水西景，顧我方聽夜半鐘。", "莫計升沉須强飯，男兒愛惜鬢星鬆。"]'),
('4dfc7a9d-0674-459d-81ed-c194e69eda9f','因振之之行過新昌懷鮑清卿','許及之','宋','宋诗','song-poetry','','[]','新昌令尹鮑參軍，中的聲名孰似君。',64,'全唐诗/poet.song.152000.json','["新昌令尹鮑參軍，中的聲名孰似君。", "未免徒勞紆墨綬，不教平步上青雲。", "句如冰柱當庚伏，心似秋空納世氛。", "豈爲求齊工鼓瑟，知音合遣九霄聞。"]'),
('70235cd5-24ae-40d6-8923-69f6fed1b433','懷轉庵餞客','許及之','宋','宋诗','song-poetry','','[]','一水經行昔飽諳，故鄉真似是淮南。',64,'全唐诗/poet.song.152000.json','["一水經行昔飽諳，故鄉真似是淮南。", "杏花巖畔春携酒，楊柳堂前夜駐驂。", "鄰境不停科甲馬，吾民常喜足田蠶。", "風謠物色堪詩句，餞客歸時問轉庵。"]'),
('043d1b17-d40f-4adc-946d-c4d8ccc21230','南省簾外唱和五首  其一','許及之','宋','宋诗','song-poetry','','[]','句讀江西獨亢宗，筆裨造化蚤論功。',64,'全唐诗/poet.song.152000.json','["句讀江西獨亢宗，筆裨造化蚤論功。", "相逢客已傳河尹，未見天教憶戴公。", "欻訝鞭鸞仙尚散，猶憐小草味能同。", "明朝遣客方公事，醉墨何妨落暮鴻。"]'),
('18bd4916-c3ef-4d75-9a44-b1b13df967d0','南省簾外唱和五首  其二','許及之','宋','宋诗','song-poetry','','[]','寒似西來不立宗，酒兵屢敵故難功。',64,'全唐诗/poet.song.152000.json','["寒似西來不立宗，酒兵屢敵故難功。", "詩成染筆能忙事，勘罷糊名也自公。", "細雨燒燈驚節過，清尊華髮與君同。", "故園花訊新來少，欲問平安無過鴻。"]'),
('7f88aa80-8bc5-4e63-b735-3e9daa63f1d6','南省簾外唱和五首  其三','許及之','宋','宋诗','song-poetry','','[]','畫史何人更姓吳，梁園重與續成圖。',64,'全唐诗/poet.song.152000.json','["畫史何人更姓吳，梁園重與續成圖。", "晴泥正好一犁雨，歸思還先六幅蒲。", "院鎖餘寒春力峭，書殘午後客情孤。", "新詩剩喜相料理，已覺胸中隘五湖。"]'),
('061f0e87-ccaa-48cb-8d1d-ca5038f31ddb','南省簾外唱和五首  其四','許及之','宋','宋诗','song-poetry','','[]','桃李枝頭鎖沍寒，天工一笑發嫣然。',64,'全唐诗/poet.song.152000.json','["桃李枝頭鎖沍寒，天工一笑發嫣然。", "喚回雪苑陽春脚，幻出瓊壺小有天。", "欻看南圖羊角上，恍思西抹阿婆年。", "政須點勘頻呵護，準擬開函近御筵。"]'),
('44eefd5f-27a3-4fa3-bf9a-8432bd997a2a','南省簾外唱和五首  其五','許及之','宋','宋诗','song-poetry','','[]','不因呵手軸書簾，顓帝司寒盍解嚴。',64,'全唐诗/poet.song.152000.json','["不因呵手軸書簾，顓帝司寒盍解嚴。", "已放官梅撩杜老，更堪園柳憶陶潛。", "定無裁鑒追王謝，敢別妍媸擯嫫鹽。", "爾許空餐已知愧，底須自喜作沾沾。"]'),
('df56fac9-b4a7-4e56-a9e8-c199ae905c27','次韻留守劉觀文鹿鳴之什','許及之','宋','宋诗','song-poetry','','[]','一時天府姓名登，三載文翁禮俗型。',64,'全唐诗/poet.song.152000.json','["一時天府姓名登，三載文翁禮俗型。", "已著衮衣親勸駕，更施燕席共談經。", "杏園路逐三春暖，星漢槎通八月靈。", "聖策若詢黄髮老，爲言輕重繫朝廷。"]'),
('aab8f65d-f69a-43be-916f-314ae6f8266e','劉正言講筵視職初直玉堂見案上所和高紫微陽字詩寵和二章見示因用韻答以一首深愧短拙','許及之','宋','宋诗','song-poetry','','[]','措世規模豈小康，八荒壽域萬年觴。',64,'全唐诗/poet.song.152000.json','["措世規模豈小康，八荒壽域萬年觴。", "諫行膏澤苕溪水，講勸淵源養浩堂。", "遇合共欣魚縱壑，闊希真見鳳朝陽。", "簷花細雨金鑾直，預卜爲霖喜色黄。"]'),
('109ddb6f-b735-494a-b9fb-5cf92d798221','次韻常之歲晚督才叔詩課','許及之','宋','宋诗','song-poetry','','[]','流年舍我疾於飛，受歲於予孰敢違。',64,'全唐诗/poet.song.152000.json','["流年舍我疾於飛，受歲於予孰敢違。", "有愧淵明新覺是，自憐伯玉舊知非。", "盍簪烈炬昏騎馬，博簺相歡夜倒衣。", "豈復少年豪氣事，詩壇聊爲解堅圍。"]'),
('a45aacf9-2a04-48d5-8a06-a47cd0dd36d1','次韻盧次夔直學投贈二首盧之父有師法方訓長孫鑄而次夔近繹子屈致教參孫發蒙  其一','許及之','宋','宋诗','song-poetry','','[]','大難過訪憶曾酬，謁入徒慙刺字留。',64,'全唐诗/poet.song.152000.json','["大難過訪憶曾酬，謁入徒慙刺字留。", "惠我新詩堪照夜，喜君逸氣正橫秋。", "時哉好去陳三策，老者那能畫一籌。", "暇日太丘如共款，忘炊肯更作糜不。"]'),
('173f8924-6e40-4308-b1c6-4730cff5905a','次韻盧次夔直學投贈二首盧之父有師法方訓長孫鑄而次夔近繹子屈致教參孫發蒙  其二','許及之','宋','宋诗','song-poetry','','[]','老眼青燈字字愁，猶能宅勝復棲幽。',64,'全唐诗/poet.song.152000.json','["老眼青燈字字愁，猶能宅勝復棲幽。", "要追野叟田夫輩，願作漁鄉橘里侯。", "蚤取科名辭舉業，來陪散吏入詩流。", "小孫勤苦童蒙訓，未解知名杜若洲。"]'),
('63e6db74-6063-4f69-8204-e3910860f3c8','約轉庵','許及之','宋','宋诗','song-poetry','','[]','半夜月明晨起風，不眠附火鬢搔蓬。',64,'全唐诗/poet.song.152000.json','["半夜月明晨起風，不眠附火鬢搔蓬。", "窗虛灑急疑霰集，閤暖香微知菊叢。", "便擬南枝開摘索，只愁卯酒醉冬烘。", "行吟真愛亭前路，梅蕊已如椒子紅。"]'),
('c8dc1113-7f83-4479-8b5f-f7d10b69965e','百七丈和篇有盡道溫柔別有鄉誰知絳闕水茫茫之句意有屬也再用韻奉酬  其一','許及之','宋','宋诗','song-poetry','','[]','仙凡從昔各爲鄉，弱水蓬萊隔混茫。',64,'全唐诗/poet.song.152000.json','["仙凡從昔各爲鄉，弱水蓬萊隔混茫。", "不見麻姑呈狡獪，空教賀老號清狂。", "兩奩心事無人共，萬點花飛有底忙。", "說與東風須作主，莫教癡白妬嬌黄。"]'),
('b76e5029-230a-41c3-9572-22b4aba1885e','百七丈和篇有盡道溫柔別有鄉誰知絳闕水茫茫之句意有屬也再用韻奉酬  其二','許及之','宋','宋诗','song-poetry','','[]','休厭黄鸝百囀聲，詩翁亦是不平鳴。',64,'全唐诗/poet.song.152000.json','["休厭黄鸝百囀聲，詩翁亦是不平鳴。", "中年懷抱愁離別，暇日親朋好會并。", "踏損落紅無錦襪，吟成白雪有朱英。", "欄桿徙倚空三歎，雨後斜陽寫不成。"]'),
('8375ffc7-76bc-4b8a-8c0c-8da7f8a2891f','百七丈寒食扁舟之盟遽寒姚黄恐成輕負輒賦二篇復以酴醾爲約  其一','許及之','宋','宋诗','song-poetry','','[]','閒中直指醉爲鄉，寒食扁舟竟渺茫。',64,'全唐诗/poet.song.152000.json','["閒中直指醉爲鄉，寒食扁舟竟渺茫。", "可惜海棠隨雨過，猶憐粉蝶伴醒狂。", "游人靜後西山好，春事深來老圃忙。", "未必煩公頻折簡，花時還是負姚黄。"]'),
('a1932a2b-e71e-4a1e-a3de-d05c39b2b961','百七丈寒食扁舟之盟遽寒姚黄恐成輕負輒賦二篇復以酴醾爲約  其二','許及之','宋','宋诗','song-poetry','','[]','連夕驚雷非惡聲，池塘閤閤幾蛙鳴。',64,'全唐诗/poet.song.152000.json','["連夕驚雷非惡聲，池塘閤閤幾蛙鳴。", "春程尚有三之一，樂事那能四者并。", "養得苔錢都滿砌，足爲花地藉殘英。", "聞閒不惜衝泥過，架上酴醾玉已成。"]'),
('8f397e50-46ea-490d-804a-d45e16da1190','謝觀復長髯垂膝儼然山澤之癯棄去儒業從皇甫道士於廬阜余見之三茅以所編老君實錄見贈賦此奉酬','許及之','宋','宋诗','song-poetry','','[]','真是儒仙藪澤姿，長髯合住謝家池。',64,'全唐诗/poet.song.152000.json','["真是儒仙藪澤姿，長髯合住謝家池。", "香爐峯下看雲坐，碧玉壺中倒景窺。", "妙旨五千歸日用，纂言十萬見宗師。", "故交幡起逃儒恨，不值青藜夜訪時。"]'),
('b44594b1-964b-4f0c-9bd8-c75f239488df','酬劉孝若二首  其一','許及之','宋','宋诗','song-poetry','','[]','春去堂堂已浹旬，幽花耿耿尚能春。',64,'全唐诗/poet.song.152000.json','["春去堂堂已浹旬，幽花耿耿尚能春。", "細思造物尤恩我，晚著家山剩庇身。", "客至情親惟話舊，詩成意足不求新。", "長年道路多疎隔，如子相過正要頻。"]'),
('76e97a50-fddd-4040-a497-ecbbff5963dd','酬劉孝若二首  其二','許及之','宋','宋诗','song-poetry','','[]','回首城南同舍時，參辰相望更爲誰。',64,'全唐诗/poet.song.152000.json','["回首城南同舍時，參辰相望更爲誰。", "杜門正愧衰兼懶，枉句多慙頌不規。", "新竹篩金鳴粉籜，初荷擎蓋弄紋漪。", "小園景物堪供給，剝啄何時共說詩。"]'),
('495efe9c-51e9-41ab-97a6-784b4079b49f','次韻酬王宣甫','許及之','宋','宋诗','song-poetry','','[]','老去才衰非曩時，如今何處有新詩。',64,'全唐诗/poet.song.152000.json','["老去才衰非曩時，如今何處有新詩。", "陶溪已過黄初作，漳浦曾同鄭老期。", "近喜高軒能肯顧，翻催歸棹起相思。", "杖藜固有慇懃約，逸駕愁難十駕隨。"]'),
('597475b9-5788-43d6-9315-307a5a6db7ac','奉酬沈仲歸','許及之','宋','宋诗','song-poetry','','[]','劉牆屈壘敵金湯，今繼薰風寫拒陽。',64,'全唐诗/poet.song.152000.json','["劉牆屈壘敵金湯，今繼薰風寫拒陽。", "久住揚州詩富艷，暫歸孤嶼句清凉。", "簷聲疊喜隨花落，野色方期共竹光。", "偶苦河魚今少愈，不應樽酒負鵝黄。"]'),
('f76b0cd2-713e-412b-9987-6c8428901d4a','次韻酬才叔仍送酒','許及之','宋','宋诗','song-poetry','','[]','逸駕翩翩莫可攀，飛騰豈久住鄉間。',64,'全唐诗/poet.song.152000.json','["逸駕翩翩莫可攀，飛騰豈久住鄉間。", "秋風便起東西玉，郢雪姑吟大小山。", "僅喜借居鄰竹院，能無持酒到松關。", "樓成約共魚軒過，急遺雙壺且破顔。"]'),
('55549b3f-6872-4cee-863b-71edf2d681ed','再用韻酬才叔','許及之','宋','宋诗','song-poetry','','[]','試聽剝啄莫尋推，竹院來過更有誰。',64,'全唐诗/poet.song.153000.json','["試聽剝啄莫尋推，竹院來過更有誰。", "紫鳳迎門披裋褐，小龍入臼破新規。", "映空白鷺排青障，照水黄鸝點碧漪。", "春去自應留物色，眼前何事不供詩。"]'),
('36581e8a-046e-46d4-ac3a-397722ae1992','融州和孝若韻見寄併謝真愛賞梅之集復次韻奉酬  其一','許及之','宋','宋诗','song-poetry','','[]','城南家訓不籯金，曾共青燈課夜吟。',64,'全唐诗/poet.song.153000.json','["城南家訓不籯金，曾共青燈課夜吟。", "往行二劉元作則，後人六藝盡師心。", "經傳鄉派源流遠，詩到孫枝志思深。", "玉潤風流今鮑叔，卜鄰佳處到于今。"]'),
('9eea4ee6-972e-49d0-9308-c262f63fd374','融州和孝若韻見寄併謝真愛賞梅之集復次韻奉酬  其二','許及之','宋','宋诗','song-poetry','','[]','同病齊年各老成，喜君勿藥近安平。',64,'全唐诗/poet.song.153000.json','["同病齊年各老成，喜君勿藥近安平。", "籃輿不惜尋梅過，藜杖何妨倒屣迎。", "潘令劇談聽至夜，劉郎新句和來清。", "疾行每愧穿楊手，金榜君居第十名。"]'),
('89cc3d52-b98e-43bc-a9da-f4380f56ed29','次韻酬石謙伯二首  其一','許及之','宋','宋诗','song-poetry','','[]','拂雲著句未能奇，聊爲溪山且發微。',64,'全唐诗/poet.song.153000.json','["拂雲著句未能奇，聊爲溪山且發微。", "過矣瓊瑶煩答贈，居然懷袖有光輝。", "經時苦雨無佳思，幾日占晴望落暉。", "石友不來春自老，登山臨水送春歸。"]'),
('20003d4d-6308-4ea9-8792-a47a0cc8523f','次韻酬石謙伯二首  其二','許及之','宋','宋诗','song-poetry','','[]','石兄兄石不兄錢，卜築山邊復水邊。',64,'全唐诗/poet.song.153000.json','["石兄兄石不兄錢，卜築山邊復水邊。", "位置亭臺依茂密，剔疏巖壑聽潺湲。", "拂雲脩竹還通月，擎蓋高松不記年。", "預恐陶君回俗駕，擬乘下澤疾驅前。"]'),
('eb6b8ad1-bc5f-4c56-9ea5-80a9b88e6dcb','酬木伯初仍簡才叔常之','許及之','宋','宋诗','song-poetry','','[]','惠我詩章有琢磨，傳家學力見功多。',64,'全唐诗/poet.song.153000.json','["惠我詩章有琢磨，傳家學力見功多。", "恍驚社裏摛文手，奪得天邊織錦梭。", "競約芳洲容與戲，預欣清夜醉時歌。", "熏蒸浪泊看鳶墮，不念垂垂老伏波。"]'),
('22d7acb7-e3d7-41d5-86aa-6a88bc41912a','次韻酬潘才叔','許及之','宋','宋诗','song-poetry','','[]','杜老添愁憐晦日，閬仙不睡惜殘春。',64,'全唐诗/poet.song.153000.json','["杜老添愁憐晦日，閬仙不睡惜殘春。", "閏餘寬我花枝眼，年事逾君卦氣身。", "架上酴醾香已歇，階前紅藥色方新。", "新晴肯訪山園否，聞健聞閒莫厭頻。"]'),
('d3a75515-4c2f-43eb-aa0f-31f9f496dcfb','再酬同社','許及之','宋','宋诗','song-poetry','','[]','殷勤春事尚彌旬，豈是榆錢買得春。',64,'全唐诗/poet.song.153000.json','["殷勤春事尚彌旬，豈是榆錢買得春。", "映水殘陽開句眼，滿園新綠庇花身。", "論文把酒交情舊，對弈忘機局面新。", "信筆題詩無好語，多情烏鵲喜聲頻。"]'),
('3fae1cac-06d4-4dfe-90ce-ec15ebf83fd9','酬沈仲歸  其一','許及之','宋','宋诗','song-poetry','','[]','曾倚平山望遠峯，橋過真主昔回龍。',64,'全唐诗/poet.song.153000.json','["曾倚平山望遠峯，橋過真主昔回龍。", "詞翻十事溫卿閲，句敵三都蜀嶺筇。", "置驛家風羅四面，揮毫帥守角千鍾。", "來歸肯作蕭閒伴，一誦新篇一起容。"]'),
('c8e15ca8-cae4-4c7f-a3c3-1710cd7e1fb0','酬沈仲歸  其二','許及之','宋','宋诗','song-poetry','','[]','田家渴雨望雲峯，掣電驅雷起蟄龍。',64,'全唐诗/poet.song.153000.json','["田家渴雨望雲峯，掣電驅雷起蟄龍。", "喜極三農俱合爪，爭扶百拜各拋筇。", "先生不用愁經笥，老子惟須辦飲鍾。", "換韻題詩應有句，何人起舞爲予容。"]'),
('39a49e24-6877-41ce-86bc-8d239a23ef3f','次韻酬梅南壽舊曾和予梅花詞','許及之','宋','宋诗','song-poetry','','[]','衣鉢歐梅無別峯，天慳發處妙屠龍。',64,'全唐诗/poet.song.153000.json','["衣鉢歐梅無別峯，天慳發處妙屠龍。", "瓊瑶有句傳商鼎，金石留聲在蜀筇。", "三歎少曾賡俚曲，五音全得列編鍾。", "末章壓倒君餘事，不道承家有愧容。"]'),
('95087d26-eb15-4f29-a992-fb84b44b4607','自和','許及之','宋','宋诗','song-poetry','','[]','凈盡繁紅但碧峯，藥欄猶有綠盤龍。',64,'全唐诗/poet.song.153000.json','["凈盡繁紅但碧峯，藥欄猶有綠盤龍。", "風光何限供吟筆，霜鬢儘添宜老筇。", "豈必愁來方酌酒，底須句到始撞鍾。", "閒中作樂真吾事，多謝天工久見容。"]'),
('a7123157-9d24-4cd9-a2a4-1c77e883b977','用韻酬常之才叔','許及之','宋','宋诗','song-poetry','','[]','西山爽氣挾蓮峯，礙眼何嘗恕籜龍。',64,'全唐诗/poet.song.153000.json','["西山爽氣挾蓮峯，礙眼何嘗恕籜龍。", "近種貓頭未成竹，擬求人面替扶筇。", "春歸意緒愁千斛，病起情悰酒一鍾。", "莫話朝雞萌妄想，形骸老醜若爲容。"]'),
('f09b4eb0-003c-4949-865e-d7bb06e4fa97','酬翁常之次韻','許及之','宋','宋诗','song-poetry','','[]','雲間聲價仰高峯，今向詩中識士龍。',64,'全唐诗/poet.song.153000.json','["雲間聲價仰高峯，今向詩中識士龍。", "傳誦廢餐惟閣筆，行吟須杖轉思筇。", "晚欣鄉里才華盛，故是江山秀氣鍾。", "竹院過從煩答似，坐來起敬有羞容。"]'),
('e2324c62-28ac-4129-b001-f7f626eb9145','再酬梅南壽','許及之','宋','宋诗','song-poetry','','[]','看雲注日愛奇峯，撼壁魚梭欲化龍。',64,'全唐诗/poet.song.153000.json','["看雲注日愛奇峯，撼壁魚梭欲化龍。", "鳳沼催詩欣在手，驪珠奪目急扶筇。", "老慙尚竊祠庭祿，閒覺驚聞夜漏鍾。", "報答一春無好語，更憐同社曲優容。"]'),
('87512c9d-d368-41e2-ab9f-7822e03c3592','用韻酬常之','許及之','宋','宋诗','song-poetry','','[]','老慙匿影愛嵐峯，已愧家聲昔二龍。',64,'全唐诗/poet.song.153000.json','["老慙匿影愛嵐峯，已愧家聲昔二龍。", "鑿井得泉思種橘，尋河知路記因筇。", "加餐漫說囊中法，應俗多違飯後鍾。", "同社朋來欣已諾，何時倒屣却從容。"]'),
('1b68a688-596a-4852-a510-8d52593a8ecb','疊用韻酬常之','許及之','宋','宋诗','song-poetry','','[]','迢迢起頓兩三峯，石窟門邊有斷龍。',64,'全唐诗/poet.song.153000.json','["迢迢起頓兩三峯，石窟門邊有斷龍。", "致爽君能豪拄笏，策疲我愧老搘筇。", "論詩句句諧唐律，舉酒時時敵漢鍾。", "謝客分留餘物色，可能無意更形容。"]'),
('1d794cb9-5fd9-46e9-b56b-94bc4e7ceb9b','用韻酬侯居甫','許及之','宋','宋诗','song-poetry','','[]','玉樹風前映玉峯，吾家安得此乘龍。',64,'全唐诗/poet.song.153000.json','["玉樹風前映玉峯，吾家安得此乘龍。", "書林未照青藜杖，甥館肯陪高節筇。", "歸棹喜聞明月載，哦詩想带夕陽鍾。", "從今社裏添光寵，咳唾珠璣有仲容。"]'),
('fea6f777-3254-424f-ac81-732cf6767b38','再用韻酬居甫','許及之','宋','宋诗','song-poetry','','[]','凌雲健筆聳雲峯，奪得標歸信是龍。',64,'全唐诗/poet.song.153000.json','["凌雲健筆聳雲峯，奪得標歸信是龍。", "官似梅仙非素隠，山經謝屣伴栖筇。", "柳邊待起明光草，花外要聞長樂鍾。", "暫肯聞閒入詩社，來篇三復歎南容。"]'),
('41885407-e833-4efa-9b5a-ce3c9f8d3cda','酬鄭千之','許及之','宋','宋诗','song-poetry','','[]','契託尊公千佛名，思瞻生氣屬丹青。',64,'全唐诗/poet.song.153000.json','["契託尊公千佛名，思瞻生氣屬丹青。", "愛君克肖充眉宇，將母通家過里亭。", "難韻更能陪我和，苦吟想見徹鄰聽。", "勉傳衣鉢窮年計，入學元非一仲丁。"]'),
('88f53303-1e94-4a74-8314-dc16dd85dd3d','自和','許及之','宋','宋诗','song-poetry','','[]','擾擾人生漫百營，思量蒲柳豈長青。',64,'全唐诗/poet.song.153000.json','["擾擾人生漫百營，思量蒲柳豈長青。", "四時代謝真郵傳，百歲光陰寄客亭。", "眼底浮華非我有，靜中真樂要人聽。", "故吾不惜全還我，二十三前是白丁。"]'),
('5ab8fea6-8c13-48ef-9fe6-af2b5ef6657f','和居甫仍喜其得雄','許及之','宋','宋诗','song-poetry','','[]','歸巢倦翼底須營，家近容成取次青。',64,'全唐诗/poet.song.153000.json','["歸巢倦翼底須營，家近容成取次青。", "笑我崎嶇山上路，羨君瀟灑竹間亭。", "弄璋已覺門闌喜，引玉尤驚里衖聽。", "得子且欣容易養，庚壬乙丙况藏丁。"]'),
('7e6fdf39-6582-400e-8312-078ef8b0da5b','德久寄南游詩卷內和丁字韻凡九因次韻寄酬','許及之','宋','宋诗','song-poetry','','[]','三逕雖荒可更營，歸來因得課樵青。',64,'全唐诗/poet.song.153000.json','["三逕雖荒可更營，歸來因得課樵青。", "巖棲寧著高低屐，世路怕過長短亭。", "厚祿故人新枉句，高山流水舊知聽。", "案頭展卷勤收拾，却恐天官敕六丁。"]'),
('b463a10c-3b15-48e8-9caf-59375ac1b13f','酬常之','許及之','宋','宋诗','song-poetry','','[]','連朝晴霽有何營，靜對脩篁照眼青。',64,'全唐诗/poet.song.153000.json','["連朝晴霽有何營，靜對脩篁照眼青。", "旌節花迎門外客，發揚荷傍水邊亭。", "雙呼鳩語元無據，一箇蟬聲已可聽。", "鵲鵲飛來還送喜，吉丁新句遣家丁。"]'),
('cf950007-3f04-4ee8-814c-187aca1d3f7f','奉酬常之仙藥課畦丁之什','許及之','宋','宋诗','song-poetry','','[]','在勤生計合勤營，手劚山園藥甲青。',64,'全唐诗/poet.song.153000.json','["在勤生計合勤營，手劚山園藥甲青。", "首辨君臣嚴位置，次看炎冷各調亭。", "有身爲患那能見，未說能仙自喜聽。", "肘後傳來須記取，種時端是戊銜丁。"]'),
('fa5fded4-cef7-40b5-b277-7e04045dbcc1','酬孝若','許及之','宋','宋诗','song-poetry','','[]','自笑求田了不營，竭貲結屋爲山青。',64,'全唐诗/poet.song.153000.json','["自笑求田了不營，竭貲結屋爲山青。", "尚憐遠岫光傾座，猶欲平崖穩著亭。", "同社唱酬雖數至，扣門剝啄未嘗聽。", "故交要識今吾面，不是遺民即隠丁。"]'),
('2e229853-9167-4309-9989-014ac7f5235e','酬南壽  其一','許及之','宋','宋诗','song-poetry','','[]','窮當堅似亞夫營，誰似任安事衛青。',64,'全唐诗/poet.song.153000.json','["窮當堅似亞夫營，誰似任安事衛青。", "欲使威儀還漢舊，未傷風景隔新亭。", "功名薄處書慵讀，志節高邊我愛聽。", "過午尚思茶一碗，休將後蔡比前丁。"]'),
('ebbe6800-d44f-4394-807d-95633ef36902','酬南壽  其二','許及之','宋','宋诗','song-poetry','','[]','身世悠悠莫苦營，是他松柏只長青。',64,'全唐诗/poet.song.153000.json','["身世悠悠莫苦營，是他松柏只長青。", "寬於繭甕茨爲舍，大似雞棲草作亭。", "蟲臂鼠肝元自定，龜毛兔角慣曾聽。", "臚傳天語君須記，第四科名合是丁。"]'),
('96a01f35-1b51-4cce-8689-bd0c73471b1a','仲歸以結局丁字韻二詩七夕乃連和四篇至如數奉酬  其一','許及之','宋','宋诗','song-poetry','','[]','年衰病怯思怔營，惟見詩筩眼便青。',64,'全唐诗/poet.song.153000.json','["年衰病怯思怔營，惟見詩筩眼便青。", "連和舊篇纔結局，高吟新月恰當亭。", "敢輕勍敵嬰生力，正恐陳言厭熟聽。", "入社莫言詩殿後，此時孤律夢方丁。"]'),
('da78cdba-afbc-449e-b043-67c0564b595f','仲歸以結局丁字韻二詩七夕乃連和四篇至如數奉酬  其二','許及之','宋','宋诗','song-poetry','','[]','君詩紀律似堅營，氣王東南幟赤青。',64,'全唐诗/poet.song.153000.json','["君詩紀律似堅營，氣王東南幟赤青。", "湧思急於流峽水，疾馳快似速郵亭。", "想當愜意須頻讀，說與齊眉更喜聽。", "擊鉢工夫勝刻楮，賣文却笑隠吾丁。"]'),
('f52d751b-26db-4e7f-98ac-b058da63418d','仲歸以結局丁字韻二詩七夕乃連和四篇至如數奉酬  其三','許及之','宋','宋诗','song-poetry','','[]','年逾卦氣易身營，除一君猶鬢發青。',64,'全唐诗/poet.song.153000.json','["年逾卦氣易身營，除一君猶鬢發青。", "豈但文章難匹敵，只量筋力敢秤亭。", "詩如博弈聊賢已，調似渝歌且易聽。", "除却吟哦無一事，齋心惟敬六神丁。"]'),
('07f3c0cb-fa1a-450d-ba59-b53a8bb4366a','仲歸以結局丁字韻二詩七夕乃連和四篇至如數奉酬  其四','許及之','宋','宋诗','song-poetry','','[]','聘錢猶欠入驅營，野語傳訛亂史青。',64,'全唐诗/poet.song.153000.json','["聘錢猶欠入驅營，野語傳訛亂史青。", "河鼓牛郎隔河漢，成橋烏鵲爲津亭。", "隨緣樂事從心賞，妄想佳期莫耳聽。", "見說老人星合見，更占秋丙看春丁。"]'),
('2451c5ab-e894-41e1-aba0-e1677f1ac6e6','次韻湘西許老','許及之','宋','宋诗','song-poetry','','[]','困倚床頭未當癡，結廬取次不塗茨。',64,'全唐诗/poet.song.153000.json','["困倚床頭未當癡，結廬取次不塗茨。", "常留真火添丹竈，任使清霜上兩眉。", "入市有錢時施藥，還家無藁自吟詩。", "不因乘興來過我，老子姓名誰得知。"]'),
('3cb20309-e98f-46c2-ab46-f1d9b47384c6','次韻王宣甫','許及之','宋','宋诗','song-poetry','','[]','佳句馳來合斬關，家童豈得嫉渠頑。',64,'全唐诗/poet.song.153000.json','["佳句馳來合斬關，家童豈得嫉渠頑。", "好懷偶苦催租至，厚意虛教垂橐還。", "近社賡酬幾寂寞，舊詩塗改厪爛斑。", "轉庵方示維摩病，猶望崇齋大小山。"]'),
('b2402877-85b7-4081-9eeb-6861db5263ac','次韻孝若謝報謁二首  其一','許及之','宋','宋诗','song-poetry','','[]','訪舊論交憶斷金，閉門宣想日高吟。',64,'全唐诗/poet.song.153000.json','["訪舊論交憶斷金，閉門宣想日高吟。", "應思后牧長回首，更學陰何苦用心。", "顧我自知經世淺，如君何苦愛人深。", "相逢休說東山話，已覺昨非猶至今。"]'),
('d4bbe0bf-35fa-4462-9b48-da34246854b9','次韻孝若謝報謁二首  其二','許及之','宋','宋诗','song-poetry','','[]','如懸夜雨潤冬晴，菜本朝來翠浪平。',64,'全唐诗/poet.song.153000.json','["如懸夜雨潤冬晴，菜本朝來翠浪平。", "菊老容成宜退聽，梅開真愛欲相迎。", "擁爐靜坐心非想，把筆題詩思過清。", "寫寄城西老朋友，數能過訪不無名。"]'),
('68c4443c-b893-4a9f-93df-ffc5e1f61266','次韻盧康伯別家塾後示惠二詩  其一','許及之','宋','宋诗','song-poetry','','[]','投老投閒袖久通，何妨搔首鬢如蓬。',64,'全唐诗/poet.song.153000.json','["投老投閒袖久通，何妨搔首鬢如蓬。", "故人索我形骸外，春事開予笑語中。", "別去未幾情似闊，詩成倏至福何洪。", "倦從遠役寧株守，人訝相從臭味同。"]'),
('44a5d7bb-c26c-4858-a06d-24650bd0b3c4','次韻盧康伯別家塾後示惠二詩  其二','許及之','宋','宋诗','song-poetry','','[]','如君摸索不難知，匡鼎來時解說詩。',64,'全唐诗/poet.song.153000.json','["如君摸索不難知，匡鼎來時解說詩。", "莫作瓜分甜後蒂，已拚樗散鬢成絲。", "聞閒歲月壺中永，取靜光陰隙外馳。", "莫道廣文心似鐵，知心猶有賦梅詩。"]'),
('2b0c1d94-6dca-4474-802d-3c4243046d52','次諫長韻  其一','許及之','宋','宋诗','song-poetry','','[]','繚垣虛晝靜沉沉，兩行槐陰一徑深。',64,'全唐诗/poet.song.153000.json','["繚垣虛晝靜沉沉，兩行槐陰一徑深。", "細雨入簾供洪溽，清談參坐共蕭森。", "柳邊花底隨官事，綠暗紅稀惜壯心。", "正以頭風無藉在，詩翁佳句敵陳琳。"]'),
('986fa921-e936-4a5c-a7c0-7ca2000bf5d4','次諫長韻  其二','許及之','宋','宋诗','song-poetry','','[]','簷溜涓涓響澗涔，濕飛蝴蝶見深深。',64,'全唐诗/poet.song.153000.json','["簷溜涓涓響澗涔，濕飛蝴蝶見深深。", "乳鴉雛雀自酬答，老柳古槐惟蔚森。", "同省三人慙未至，許身一字愧初心。", "妤風隔院動修竹，隨意題詩傾碧琳。"]'),
('a54a856e-8ad7-4fbc-9300-a6825c8a6c1d','再次仲歸臨池韻','許及之','宋','宋诗','song-poetry','','[]','聖時下士若卷阿，鴻筆詞源走萬波。',64,'全唐诗/poet.song.153000.json','["聖時下士若卷阿，鴻筆詞源走萬波。", "南省只教韓愈到，北飛猶障禹門過。", "男兒器業偏成晚，夫子才名獨患多。", "地闢天開知有日，中興宜頌更宜歌。"]'),
('fae0b1ec-a3e4-47e7-9c63-53b0eae2082b','次韻劉孝若二首  其一','許及之','宋','宋诗','song-poetry','','[]','每思忝竊長知愧，何有行藏可待明。',64,'全唐诗/poet.song.153000.json','["每思忝竊長知愧，何有行藏可待明。", "壯不如人祇錄錄，老將及耄更平平。", "故交契予情文厚，佳句馳來格律清。", "擬策疲駑追逸步，却愁重趼趣脩程。"]'),
('24badf63-d772-4b4c-a22d-98ed95078798','次韻劉孝若二首  其二','許及之','宋','宋诗','song-poetry','','[]','宜男草長欲忘憂，含笑花開却似羞。',64,'全唐诗/poet.song.153000.json','["宜男草長欲忘憂，含笑花開却似羞。", "轉蕙有風凉意動，重梅過雨漲痕留。", "幽閒歲月難消受，香火朝昏未答酬。", "珍重友朋相慰藉，鼎來賡和得因由。"]'),
('350cf401-c167-475e-85a9-b5d071c452d7','次韻轉庵幽禽到研邊之什','許及之','宋','宋诗','song-poetry','','[]','梅風拂拂動薰絃，久雨休疑是漏天。',64,'全唐诗/poet.song.153000.json','["梅風拂拂動薰絃，久雨休疑是漏天。", "有客方懷吟澤畔，無樓那得住山邊。", "添香遣日愁難破，換韻傳詩喜欲顛。", "犯戒成章賢博弈，門人已廢蓼莪篇。"]'),
('abca887c-8efa-4820-86ce-cfa49cf09028','次潘茂和韻','許及之','宋','宋诗','song-poetry','','[]','久向竹林聞小阮，恨無此客豈無氈。',64,'全唐诗/poet.song.153000.json','["久向竹林聞小阮，恨無此客豈無氈。", "文章未可爲餘事，子弟何妨自太鮮。", "老去懶兼衰作病，傳來詩與月俱圓。", "瓣香合爲牀頭易，笞鳳鞭鸞不是仙。"]'),
('40e0dc8a-9cac-44e7-85c3-9a3dea87ffaa','袁同年過揚州遞書并詩再次韻約同留維揚觀春色','許及之','宋','宋诗','song-poetry','','[]','一緘書札故人情，中有新詩字字清。',64,'全唐诗/poet.song.153000.json','["一緘書札故人情，中有新詩字字清。", "郵置傳來心已醒，秋鐙讀處眼偏明。", "揚州路近帆能疾，瓜渚潮來水似生。", "少駐星軺問遺俗，春風生帳有詩呈。"]'),
('2193679d-7e74-43dd-88e6-4e3da7279cd8','再次韻仲歸','許及之','宋','宋诗','song-poetry','','[]','身名已愧鳳巢阿，世念難教古井波。',64,'全唐诗/poet.song.153000.json','["身名已愧鳳巢阿，世念難教古井波。", "老覺病時終是懶，話當情處愛相過。", "聞閒莫惜朋簪盍，服義相將戶履多。", "意到會能拚劇飲，與君同賦醉時歌。"]'),
('dc88fae7-02c0-4537-ae4f-18b3fa7f6462','席上次劉振之賢良韻','許及之','宋','宋诗','song-poetry','','[]','眼底扶疎綠漸稠，傍林軒檻轉清幽。',64,'全唐诗/poet.song.153000.json','["眼底扶疎綠漸稠，傍林軒檻轉清幽。", "空餐敢擬過僧夏，閔雨猶憐近麥秋。", "客有好懷厪夙駕，袖將佳句豁牢愁。", "焚香餉客無多景，靜聽呼雛鳥雀啁。"]'),
('3627ff2e-b148-4b24-85af-f82c6f87565d','子儀侍郎欲携家泛湖不及踐旬休之約再次韻','許及之','宋','宋诗','song-poetry','','[]','案頭故紙積如山，春去能無半日閒。',64,'全唐诗/poet.song.153000.json','["案頭故紙積如山，春去能無半日閒。", "已約旬休同此集，預愁陰雨在其間。", "時清不禁無何飲，晝永從教竟日還。", "只恐扁舟成拔宅，同遊無路可追攀。"]'),
('d2c3c506-37af-482f-8971-2db1e00b43ff','再次韻子儀侍郎用沈察院韻','許及之','宋','宋诗','song-poetry','','[]','杜宇來時憶故山，簿書叢裏且聞閒。',64,'全唐诗/poet.song.153000.json','["杜宇來時憶故山，簿書叢裏且聞閒。", "流傳舊體湖山外，賡唱新聲伯仲間。", "雨霽園林鶑亦喜，風輕簾幕燕知還。", "蘇公堤上明寒食，逸駕翩翩不可攀。"]'),
('eb5f682b-03f2-4d9c-9707-4c6d21742a2a','次王宣甫韻','許及之','宋','宋诗','song-poetry','','[]','一春無計接茵憑，野草閒花漫自榮。',64,'全唐诗/poet.song.153000.json','["一春無計接茵憑，野草閒花漫自榮。", "留得小欄紅藥在，待看新徑綠陰成。", "亦憐酒醆疎談柄，肯寄詩筒督課程。", "多病感君勤問勞，肱三折後萬緣輕。"]'),
('3e72f91e-fe89-43e1-884e-25e95a8c29c4','重陽前兩日集轉庵同社而今日忽雨次轉庵韻','許及之','宋','宋诗','song-poetry','','[]','攙先登眺高爲節，片段芙蓉錦作花。',64,'全唐诗/poet.song.153000.json','["攙先登眺高爲節，片段芙蓉錦作花。", "頼得前朝曾此集，有如今雨欲何加。", "歡濃未分玄成白，客醉猶憐酒勝茶。", "猶恨梅川無好句，更須君賦爲傳誇。"]'),
('b003b929-41e0-417b-b3b0-773f8dcbe427','次常之韻','許及之','宋','宋诗','song-poetry','','[]','身閒城市即郊坰，况是秋高氣倍清。',64,'全唐诗/poet.song.153000.json','["身閒城市即郊坰，况是秋高氣倍清。", "酬唱篇章驚句眼，往來節物見交情。", "重陽檻菊明朝摘，細雨簷花昨夜鳴。", "晚霽嘉賓不重賞，靈山空自愛嘉明。"]'),
('d0aee5d0-f5a4-4a08-84ad-ba515ffeefa6','寄陳頤剛','許及之','宋','宋诗','song-poetry','','[]','眼見交遊半陸沈，可無百丈引清深。',64,'全唐诗/poet.song.153000.json','["眼見交遊半陸沈，可無百丈引清深。", "注成兵法有奇志，閒過壯年應苦心。", "幾度梅花開悵望，有時楊葉夢追尋。", "男兒機會何終極，莫遣愁將鬢髮侵。"]'),
('489e0068-dd4d-4fc9-8d7e-691ad252852d','簡轉庵','許及之','宋','宋诗','song-poetry','','[]','扣門有礙吾何適，排戶頓疎君作難。',64,'全唐诗/poet.song.153000.json','["扣門有礙吾何適，排戶頓疎君作難。", "不對桃花傾社酒，誰憐燕子怯春寒。", "便過熟食過元巳，尚看酴醾看牡丹。", "却笑今年詩厄閏，畧無好語入毫端。"]'),
('8f0a1a72-0989-41b9-ab2e-a9ea94ec9359','簡才叔','許及之','宋','宋诗','song-poetry','','[]','坐看母竹長龍材，衣上新痕染碧苔。',64,'全唐诗/poet.song.153000.json','["坐看母竹長龍材，衣上新痕染碧苔。", "杜宇不隨春老去，黄鸝偏傍水光來。", "摇摇書带連香草，冉冉凌霄上古梅。", "此意轉庵同領解，更須潘令好懷開。"]'),
('bbd2a8f7-2b37-4088-b860-ab0d9fc177ae','寄洪州新建知縣','許及之','宋','宋诗','song-poetry','','[]','遠聽絃歌樂部封，放衙乘醉半疎慵。',64,'全唐诗/poet.song.153000.json','["遠聽絃歌樂部封，放衙乘醉半疎慵。", "家辭南越無千里，縣管西山有幾峯。", "人望廢田禾影合，吏愁空獄蘚痕重。", "孺亭應更悲前事，烟草萋萋叫夜蛩。"]'),
('8905ea39-aec8-40e0-8a8d-eb126d502e98','入南鄉檢旱紀所見','許及之','宋','宋诗','song-poetry','','[]','分宜南北兩鄉分，路入南鄉過所聞。',64,'全唐诗/poet.song.153000.json','["分宜南北兩鄉分，路入南鄉過所聞。", "蕎麥滿山明積雪，晚禾匝野漲黄雲。", "寸田必墾憐農父，五斗空餐愧令君。", "惜許早田成旱損，不成樂歲答民勤。"]'),
('9b959de7-9682-43d7-bea9-197d623828e6','紀所見','許及之','宋','宋诗','song-poetry','','[]','百年厦屋盡良材，客位經年長紫苔。',64,'全唐诗/poet.song.153000.json','["百年厦屋盡良材，客位經年長紫苔。", "失馬塞翁翻有得，撫松陶令盍歸來。", "門前婀娜千行柳，牆角輪囷一樹梅。", "滿壁圖書非詫事，錦囊成篋未曾開。"]'),
('7f2f40af-dc3d-4bad-aca2-74092d1b6caf','夜渡分宜水南','許及之','宋','宋诗','song-poetry','','[]','一水彎環抱縣流，水南物色總清幽。',64,'全唐诗/poet.song.153000.json','["一水彎環抱縣流，水南物色總清幽。", "案頭故紙看成葉，眼底青山見即愁。", "夜喚扁舟乘月渡，靜聽魚網瀝波收。", "忽思孤嶼中川畔，滿意秋風落釣鈎。"]'),
('6cea868c-b456-4f2f-a807-8dead6f6e8bc','括蒼道中次陳頤剛韻','許及之','宋','宋诗','song-poetry','','[]','詩翁四十九行年，說著行邊喜欲癲。',64,'全唐诗/poet.song.153000.json','["詩翁四十九行年，說著行邊喜欲癲。", "介婦灘頭隨水宿，馮公嶺上伴雲眠。", "趨時萍實甜于蜜，閲世匏壺老更堅。", "冀北須君空一洗，眼前駑馬太勞鞭。"]'),
('d41c1aa1-efc7-463d-a27a-76e4d8f5015c','宿建德驛追次張于湖壁間韻','許及之','宋','宋诗','song-poetry','','[]','此驛閲人多似我，于湖去後有誰來。',64,'全唐诗/poet.song.153000.json','["此驛閲人多似我，于湖去後有誰來。", "詩留版壁經年在，門對巖扃盡日開。", "天上有文修白玉，人間無句對蒼苔。", "相逢莫問滔滔事，荷蕢曾過有意哉。"]'),
('a944e0fc-9333-40b5-94d5-cd888c3bb087','舟行早起處州溪上','許及之','宋','宋诗','song-poetry','','[]','溪容霧氣撲清芬，野色微兼曉色分。',64,'全唐诗/poet.song.153000.json','["溪容霧氣撲清芬，野色微兼曉色分。", "檣表已迎山背日，纜端猶繫石根雲。", "打頭風信看來轉，當面灘聲語不聞。", "遥喚漁舟倦回首，人鷗那得更同羣。"]'),
('4d513e3c-01fa-41ca-9228-fde492360e21','早起','許及之','宋','宋诗','song-poetry','','[]','歸來百事盡摧藏，卦氣行年分所當。',64,'全唐诗/poet.song.153000.json','["歸來百事盡摧藏，卦氣行年分所當。", "未曉不眠真是老，纔明便起有何忙。", "移山種石愚翁癖，遇酒逢歌楚客狂。", "此外胸中無箇事，有時信口作篇章。"]'),
('969d6909-8deb-43f6-b944-a324d9b08517','睡起','許及之','宋','宋诗','song-poetry','','[]','飯了晴窗睡足時，杖藜徐步出荆扉。',64,'全唐诗/poet.song.153000.json','["飯了晴窗睡足時，杖藜徐步出荆扉。", "若無俗事關人意，只有楊花點客衣。", "黄鳥怨春渾不住，杜鵑知我亦思歸。", "鄰家酒熟容賒買，竹笋初生韮菜肥。"]'),
('8fa57535-57cc-4317-b48e-62095ca37c2c','書債山積久逋余丞相報緘連發二書畢喜作口號','許及之','宋','宋诗','song-poetry','','[]','自思堪笑亦堪憐，懶與頑兼不可鎸。',64,'全唐诗/poet.song.153000.json','["自思堪笑亦堪憐，懶與頑兼不可鎸。", "兩紙書成大功業，三杯酒罷小神仙。", "每當靜處常追悔，何似閒時旋補填。", "害性苦心從古病，不如歸去樂殘年。"]'),
('53b23f2b-6f25-43d2-8ed5-899c970ee59b','湯晉卿善談命求詩紀實','許及之','宋','宋诗','song-poetry','','[]','已近無聞半百年，枉煩明鏡照華顛。',64,'全唐诗/poet.song.153000.json','["已近無聞半百年，枉煩明鏡照華顛。", "湴河驛馬妨乘鄣，氐宿蒼龍分委天。", "告我三陽聞好語，驗君三命有真傳。", "預愁一字終無補，何日歸歟阿對泉。"]'),
('5af7f58b-53c4-4707-af36-00eb1954c525','德久和韻以予請外之力預爲悵然再用前韻','許及之','宋','宋诗','song-poetry','','[]','已是于思去復來，自慙無補効涓埃。',64,'全唐诗/poet.song.153000.json','["已是于思去復來，自慙無補効涓埃。", "麤官只合供煩使，昭代惟須急異才。", "名士不應詩作祟，諸公方擬管吹灰。", "且容一舸江湖去，廬阜烟蘿鎖碧嵬。"]'),
('99017d49-4095-4fd0-8a71-9ae7ff077f58','才叔調倅歸','許及之','宋','宋诗','song-poetry','','[]','五月征行思竹院，半年賡倡負松廬。',64,'全唐诗/poet.song.153000.json','["五月征行思竹院，半年賡倡負松廬。", "水西風月分歸後，衖北交朋過訪餘。", "携具洗泥曾醉否，逃禪得句定真如。", "涉齋終日攢眉坐，正頼清新爲起予。"]'),
('9a7e72f4-26ee-412b-aa3d-5f9509053523','鮑融州病足叩謁適遇孝若示融州菊詩和篇次韻呈','許及之','宋','宋诗','song-poetry','','[]','不見融州夏涉秋，居然款對豁羈愁。',64,'全唐诗/poet.song.153000.json','["不見融州夏涉秋，居然款對豁羈愁。", "猶存尊足憐同病，不繫虛舟任打頭。", "久待一州當斂惠，終煩諸野要營求。", "我今不啻便應足，獨恨於君百未酬。"]'),
('c52c6a54-54ed-44aa-a61e-b4baf72754a7','病赤目從薛山甫借荷葉巾','許及之','宋','宋诗','song-poetry','','[]','赤目朝來勢轉加，病身觀妄有生涯。',64,'全唐诗/poet.song.153000.json','["赤目朝來勢轉加，病身觀妄有生涯。", "火平文武寬心地，酒遠聖賢疏肺家。", "虛白已能生暗室，空青不用點昏花。", "小冠預擬更名字，借與團圓藕葉紗。"]'),
('534df798-12f5-4e56-8540-d4ea57ab1cb6','次韻仲歸病中垂問','許及之','宋','宋诗','song-poetry','','[]','痼疾多年久一翁，醫方驗後自難功。',64,'全唐诗/poet.song.153000.json','["痼疾多年久一翁，醫方驗後自難功。", "已慙兀者猶尊足，敢企泠然欲御風。", "覓句未能生處熟，論交正要苦辭攻。", "憑君莫話沙堤事，此語終諛不是公。"]'),
('c35ba0f2-4485-40ea-a90a-181810248e44','次韻呈支茂先賢良','許及之','宋','宋诗','song-poetry','','[]','烟蓑不盡四山青，古道長將古意評。',64,'全唐诗/poet.song.153000.json','["烟蓑不盡四山青，古道長將古意評。", "辟穀久知疎藥裹，纂言今見滿書檠。", "堯年請祝新拋隠，宋範爭抄近薦名。", "聖世埋光那可得，清臺恰奏少微明。"]'),
('461e593b-212e-4fc2-8442-3281078bdef1','喜宣甫至戲呈','許及之','宋','宋诗','song-poetry','','[]','陶溪路遠强躋攀，猶得詩筒暫往還。',64,'全唐诗/poet.song.153000.json','["陶溪路遠强躋攀，猶得詩筒暫往還。", "有便催租俄敗意，無心聽鵲忽承顔。", "菊花滿逕成三老，梅萼穿林見一斑。", "肯爲轉庵聊且住，預愁約束裹糧慳。"]'),
('dca2e113-ad57-4e60-9ae9-f1a8ce806cc4','次王宣甫題媚川圖韻','許及之','宋','宋诗','song-poetry','','[]','底須屏障寫天吳，絕境橫前與畫俱。',64,'全唐诗/poet.song.153000.json','["底須屏障寫天吳，絕境橫前與畫俱。", "兩塔屹波流不去，千帆破浪遠如無。", "空明水月光爭媚，開闔雲山妙莫摹。", "扁榜首蒙摩詰句，小亭從此有詩圖。"]'),
('ed0f5977-b4d8-4ee6-91db-8352be5949e4','韓幹四馬詩戲贈世京','許及之','宋','宋诗','song-poetry','','[]','吾聞北馬來西極，驤首躡雲無定姿。',64,'全唐诗/poet.song.153000.json','["吾聞北馬來西極，驤首躡雲無定姿。", "俯視雙瞳真皎鏡，遥憐一骨獨權奇。", "何年慘澹經營處，此日飛揚奔放時。", "把玩不須嗟歲晚，會看天廐著金羈。"]'),
('33d906d0-54a5-4efc-8444-913ae80a97c0','謝鮑潮州惠歸正李媼所作外國圖因題卷後二首  其一','許及之','宋','宋诗','song-poetry','','[]','兩年貳郡半專州，濠上魚涵惠澤游。',64,'全唐诗/poet.song.153000.json','["兩年貳郡半專州，濠上魚涵惠澤游。", "慨念中原變荆棘，圖成外國別冠裘。", "故宮禾黍悲清汴，落日風沙慘白溝。", "漢節提携曾記別，居然展卷涕橫流。"]'),
('435c48c7-01ce-4bb3-899e-822e97ac3caf','謝鮑潮州惠歸正李媼所作外國圖因題卷後二首  其二','許及之','宋','宋诗','song-poetry','','[]','健婦真能勝丈夫，丹青人物妙難摹。',64,'全唐诗/poet.song.153000.json','["健婦真能勝丈夫，丹青人物妙難摹。", "百年畫手承平久，萬折歸心守節孤。", "輒此珍藏爲我有，從渠遠致更能無。", "傷心故國流風在，不是成周王會圖。"]'),
('12704bc2-7290-49f5-ae2a-bbf2165ae1c3','題元祐諸公跋竇三川詩卷後','許及之','宋','宋诗','song-poetry','','[]','門前流水古猶今，不見鍾期但苦心。',64,'全唐诗/poet.song.153000.json','["門前流水古猶今，不見鍾期但苦心。", "每憶承平愛人物，有誰埋沒向山林。", "一官黄綬甘肥遯，百首清詩共賞音。", "自笑抱關人錄錄，亦將名字託碑陰。"]'),
('1b3d0904-ecfe-42a4-8624-8a8c1d0edd7e','次韻仲歸漁父','許及之','宋','宋诗','song-poetry','','[]','風靜波恬沒是非，雨蓑烟笠當冠衣。',64,'全唐诗/poet.song.153000.json','["風靜波恬沒是非，雨蓑烟笠當冠衣。", "移將蘭棹垂綸去，釣得金鱗带月歸。", "到處茅柴賒可準，有時蓴菜滑仍肥。", "旁人道是忘機叟，到底從來不識機。"]'),
('04cfa1a4-df98-40a2-b604-a8518763d2f5','王宣甫以新婦魚能鬬爲勝負魚有詩釋其訛謬次韻戲答','許及之','宋','宋诗','song-poetry','','[]','斕斑紅黛鬭芳塘，新婦魚兒著底忙。',64,'全唐诗/poet.song.153000.json','["斕斑紅黛鬭芳塘，新婦魚兒著底忙。", "豈爲長陵矜先後，不知濠上樂彷徉。", "詩來解辨吾伊謬，我欲兼將勝負忘。", "蚌鷸相持堪惜許，須知旁有謝三郎。"]'),
('b168073e-ea37-4136-901d-d1bf1f7d3f07','聞砧','許及之','宋','宋诗','song-poetry','','[]','秋來風物自凄清，葉葉枝枝策策鳴。',64,'全唐诗/poet.song.153000.json','["秋來風物自凄清，葉葉枝枝策策鳴。", "近砌不堪催織語，遠砧更送斷腸聲。", "苦心且作丁當和，積恨終憑熨帖平。", "寒女終身無褐彩，綺羅通夕課寒檠。"]'),
('ded26f20-e925-4148-8cde-868dce34a4de','觀郭殿巖打毬于沖天觀旁','許及之','宋','宋诗','song-poetry','','[]','峯頂毬場翦似平，汾陽號令素精明。',64,'全唐诗/poet.song.153000.json','["峯頂毬場翦似平，汾陽號令素精明。", "萬蹄攢逐一星過，兩隊歡呼衆樂鳴。", "靜看穿楊矜妙手，醉觀過翼覺身輕。", "摩挲亭下排衙石，擬賦將軍射虎行。"]'),
('c09e33dd-54ee-4168-824f-25cc0fb6ba87','聽轉庵彈琴','許及之','宋','宋诗','song-poetry','','[]','競春人去客苔侵，喜對安仁理玉琴。',64,'全唐诗/poet.song.153000.json','["競春人去客苔侵，喜對安仁理玉琴。", "百尺游絲非助我，一聲啼鴂是知音。", "湘桃作意紅兼白，碧柳隨宜淺更深。", "昨日臙脂今日雪，可憐牆角兩來禽。"]'),
('9b681f36-a7cf-473c-8f6f-cc59885656f3','次韻仲歸觀弈','許及之','宋','宋诗','song-poetry','','[]','綠陰晝靜熟觀棋，橫出寧分正與奇。',64,'全唐诗/poet.song.153000.json','["綠陰晝靜熟觀棋，橫出寧分正與奇。", "要處不容留活眼，忙時翻笑斂愁眉。", "手談大似銜枚戰，坐隠幾同過枕師。", "著罷了然無勝負，機心却許白鷗知。"]'),
('327811f2-35e7-45aa-8288-ad9899948d9f','酬轉庵畏酒之什','許及之','宋','宋诗','song-poetry','','[]','絕境夤緣有路攀，隔波樓影塔中間。',64,'全唐诗/poet.song.153000.json','["絕境夤緣有路攀，隔波樓影塔中間。", "纔收梅溽經旬雨，已放蓮峰幾朵山。", "勝處得閒真閬苑，醉餘忘世即函關。", "詩高不飲妨何事，恐對湖光自忸顔。"]'),
('5f2671d2-22fc-4e08-9fb6-ec3d48aea180','謝鮑潮州送新酒','許及之','宋','宋诗','song-poetry','','[]','濁醪青蕊作重陽，纔入開爐月果良。',64,'全唐诗/poet.song.153000.json','["濁醪青蕊作重陽，纔入開爐月果良。", "佳釀遣銷彭澤恨，好懷肯對馬軍嘗。", "清新有句須留待，風味如君不可忘。", "只俟高軒共杯酌，四時巖桂尚能香。"]'),
('81e866d3-e917-4e7d-89dd-f46ee37b4c2d','還杜叔高詩卷送酒','許及之','宋','宋诗','song-poetry','','[]','三衢三杜人能說，我亦曾闚仲叔間。',64,'全唐诗/poet.song.153000.json','["三衢三杜人能說，我亦曾闚仲叔間。", "軟語接來真有味，好詩吟到祇如閒。", "名場偪仄雲垂翅，澤國冥濛雨蔽山。", "不有客樓何地著，可無尊酒破天慳。"]'),
('20675b58-9071-4f4b-8ca4-f9d4073d6305','次韻酬顯庵寄茶','許及之','宋','宋诗','song-poetry','','[]','顯庵多別又多年，小草蠅頭越瞭然。',64,'全唐诗/poet.song.153000.json','["顯庵多別又多年，小草蠅頭越瞭然。", "覓句不爲禪所縛，住山長是佛相憐。", "無從飲酒過蓮社，尚肯分茶到玉川。", "肉食正慙無補報，歸心已駛不須鞭。"]'),
('3b626859-4f87-4476-93a4-4ba208807bbe','鄭文之許惠烏髭方戲簡','許及之','宋','宋诗','song-poetry','','[]','墮甑功名久任緣，形骸老醜孰蚩妍。',64,'全唐诗/poet.song.153000.json','["墮甑功名久任緣，形骸老醜孰蚩妍。", "了知白髮關吾事，敢學烏髭趁少年。", "人謂黄金容可作，君藏鴻寶乃能鉛。", "一皤正博妻孥笑，許惠良方試與傳。"]'),
('18e690fe-0c8a-4027-b07e-2759e3c3320c','王宣甫以予有詩求鄭文之染髭法與其舊作暗合因錄示次韻酬之','許及之','宋','宋诗','song-poetry','','[]','細看綠繞與紅圍，此地何曾著白髭。',64,'全唐诗/poet.song.153000.json','["細看綠繞與紅圍，此地何曾著白髭。", "顧我全驚緇鬢改，羨君猶有黑絲垂。", "一皤博笑幾同調，兩醜相看莫斂眉。", "正使醉中巾幘墮，不妨齊唱赤壺詞。"]'),
('43e4a22d-699a-4172-9678-34c4208934cf','戲贈','許及之','宋','宋诗','song-poetry','','[]','不鼓君家爨下材，渴心古井欲生苔。',64,'全唐诗/poet.song.153000.json','["不鼓君家爨下材，渴心古井欲生苔。", "柳枝未放行雲去，巫峽又還爲雨來。", "似染霜髭欺黑漆，尚禁醋齒試青梅。", "不妨雨過同心賞，一架酴醾花正開。"]'),
('de31933e-5ef8-452f-a4b1-8c659cd4d1b5','三賡許令姪硯之什','許及之','宋','宋诗','song-poetry','','[]','轉庵蓄硯有奇材，受墨逡巡落海苔。',64,'全唐诗/poet.song.153000.json','["轉庵蓄硯有奇材，受墨逡巡落海苔。", "異品已堪相甲乙，餘波足可畀雲來。", "許分阮姪邀金竹，預想將軍慰渴梅。", "尤物匪珍才可惜，芝蘭正要滿庭開。"]'),
('b99c07fe-44a5-49ee-95e1-ae7dd6008061','次韻王宣甫謝筆','許及之','宋','宋诗','song-poetry','','[]','筆冢前頭幾泣魚，筆耕無獲匪才疎。',64,'全唐诗/poet.song.153000.json','["筆冢前頭幾泣魚，筆耕無獲匪才疎。", "寄將毛穎煩爲傳，恰值虞卿正著書。", "千兔難酬終送似，兩家託契更誰如。", "詞章老去輸豪放，瓊玉從君要珮琚。"]'),
('6dfe287a-9a9c-4dac-9aed-0cfe7674ff1a','謝益老寄英石','許及之','宋','宋诗','song-poetry','','[]','淡交如水足生平，晚歲煩師託石兄。',64,'全唐诗/poet.song.153000.json','["淡交如水足生平，晚歲煩師託石兄。", "曾解點頭聽半偈，定能發笑驗三生。", "叢林住遍歸來好，長物分將過去輕。", "聞道肯爲鄰舍佛，錦衣只在雁山行。"]'),
('b7250c48-be92-41d1-ab79-3d146cd88bfd','舊藏英石沈儉夫族人處謝儉夫轉爲取還','許及之','宋','宋诗','song-poetry','','[]','百好殘年心已灰，石君久去絕嫌猜。',64,'全唐诗/poet.song.153000.json','["百好殘年心已灰，石君久去絕嫌猜。", "故人諾重金難比，族里言溫璧徑迴。", "曾與話禪聽翠竹，亦資醒酒卧青苔。", "如今相見休相歎，各是因人歸去來。"]'),
('ae5c39fe-81ca-4626-850f-3b4d13ca0c3a','濟叔輟案上石菖蒲爲惠石與菖蒲俱佳拙語奉酬','許及之','宋','宋诗','song-poetry','','[]','蒼然拳石具林巒，上有菖蒲八節灘。',64,'全唐诗/poet.song.153000.json','["蒼然拳石具林巒，上有菖蒲八節灘。", "洛浦毿毿餘玉珮，藍田拂拂長琅玕。", "著身便恐移天姥，濯髮還疑借洧盤。", "割愛贈予銘座右，斕斑鬢影照應難。"]'),
('ef847c9a-861d-4776-855b-e1d2c63ccc5a','賀太廟産芝草','許及之','宋','宋诗','song-poetry','','[]','太室晶瑩粲玉芝，慈闈恰遇未央時。',64,'全唐诗/poet.song.153000.json','["太室晶瑩粲玉芝，慈闈恰遇未央時。", "兩宮喜色騰堯采，萬歲歡聲動漢巵。", "發祉有來增裔葉，産祥方至在孫枝。", "從今慶事頻頻有，準擬賡歌剩賦詩。"]'),
('55e678a5-6a48-4dd7-b702-e59c3f0c017d','得禁中花喜而有作','許及之','宋','宋诗','song-poetry','','[]','階前紅少綠多時，尚有名花巨壓枝。',64,'全唐诗/poet.song.153000.json','["階前紅少綠多時，尚有名花巨壓枝。", "珠璧直疑天上得，瓊瑶難報世間奇。", "懸知丹禁鶑花繞，始覺仙家日月遲。", "珍重十洲蓬島客，津津喜色見雙眉。"]'),
('3f543b00-5a12-4c64-9b4c-0509c74d9818','再次韻宣甫探梅','許及之','宋','宋诗','song-poetry','','[]','姑射山頭冰雪姿，自應不負歲寒期。',64,'全唐诗/poet.song.153000.json','["姑射山頭冰雪姿，自應不負歲寒期。", "一枝已共巡簷笑，半樹寧忘欲雪詩。", "未許佳人和月摘，且容老子受風吹。", "城中詩社新牢落，絕喜陶山慰所思。"]'),
('14f016fa-9772-4065-9966-620e017be6e8','次韻王宣甫催梅','許及之','宋','宋诗','song-poetry','','[]','摇落驅馳自歲年，今年慙愧得身安。',64,'全唐诗/poet.song.153000.json','["摇落驅馳自歲年，今年慙愧得身安。", "小園亦有先春意，短思惟知著句難。", "看水看山從昔好，愛風愛雪待今寒。", "故人遠寄催梅作，喚起新愁有萬端。"]'),
('f4ad71b1-7e06-430e-beed-3a8f47a79dfb','再次王宣甫韻','許及之','宋','宋诗','song-poetry','','[]','江南春訊漫年年，月下推敲句未安。',64,'全唐诗/poet.song.153000.json','["江南春訊漫年年，月下推敲句未安。", "好語得來元不易，愛花開後却無難。", "霜晴屋角偏先暖，雪色枝頭已破寒。", "爲向催梅居士語，杖藜肯復過蘇端。"]'),
('565a4efb-6f01-48db-96f3-bfb424bb529d','次韻王宣甫催梅','許及之','宋','宋诗','song-poetry','','[]','犯寒時訪歲寒姿，經閏何緣却後期。',64,'全唐诗/poet.song.153000.json','["犯寒時訪歲寒姿，經閏何緣却後期。", "珍重故人勤問訊，剪裁新意作催詩。", "一陽潛與飛灰動，九奏深憑畫角吹。", "莫遣詩筩成斷絕，日來頻爲起愁思。"]'),
('c975a4f6-8187-47b1-afa1-20a8afffbfcb','初得梅花呈似參議劉二十九丈','許及之','宋','宋诗','song-poetry','','[]','江南驛使是知津，剪送瓊枝裹綠筠。',64,'全唐诗/poet.song.153000.json','["江南驛使是知津，剪送瓊枝裹綠筠。", "觸發家山春意思，喚回天地雪精神。", "護持惟有壺瓶水，映带全無几案塵。", "一夜梅坡清入夢，不妨持惱謝巖人。"]'),
('31f87106-d7ac-4e9d-b98e-9ac75595331f','張舍人惠古梅酬以拙言','許及之','宋','宋诗','song-poetry','','[]','孤標恥付壽陽粧，薜荔爲衣蘚作裳。',64,'全唐诗/poet.song.153000.json','["孤標恥付壽陽粧，薜荔爲衣蘚作裳。", "映竹蒙茸初破白，倚松鱗甲亦生香。", "分無疎影追同輩，肯逐羣英殿後芳。", "珍重折枝煩寄與，恍思千樹故山旁。"]'),
('06961bee-1665-49a5-bf1a-224a722fe811','再用韻奉酬','許及之','宋','宋诗','song-poetry','','[]','未信時新有儉粧，縞衣趺坐赤帷裳。',64,'全唐诗/poet.song.153000.json','["未信時新有儉粧，縞衣趺坐赤帷裳。", "已甘槁項終肥遯，無奈酸風發暗香。", "心苦故應如貌古，林深正不爲人芳。", "須知已是丈人行，領畧羣英顧在旁。"]'),
('5cad43c4-e9f1-49da-a16d-06e0d941ea81','同寮約過包山因問訊玉津牡丹再次韻呈子儀侍郎','許及之','宋','宋诗','song-poetry','','[]','傳聞有約過包山，節遇天祺得暫閒。',64,'全唐诗/poet.song.153000.json','["傳聞有約過包山，節遇天祺得暫閒。", "便有啼鶑迎柳外，不妨飛蝶導花間。", "東吳壯觀隨潮長，西洛風光指日還。", "獨恨微臣無補報，勳名分寸盍躋攀。"]'),
('34b9953c-c5d1-46ac-a699-a2b4ea61ccb8','謝惠牡丹','許及之','宋','宋诗','song-poetry','','[]','未歎春光去有涯，詩翁時爲送名葩。',64,'全唐诗/poet.song.153000.json','["未歎春光去有涯，詩翁時爲送名葩。", "娼條冶葉從過眼，魏紫姚黄始是花。", "洗滌壺缾晨井水，護持風雨夜窗紗。", "十眉已覺成羞澀，且向樽前領物華。"]'),
('105d8d32-1e30-4613-ada0-c9db22c56eca','趙漕從善送吳門牡丹','許及之','宋','宋诗','song-poetry','','[]','看花檐上眼長寒，慚愧鄰翁送牡丹。',64,'全唐诗/poet.song.153000.json','["看花檐上眼長寒，慚愧鄰翁送牡丹。", "和露擎來香可染，攏雲爭插玉成團。", "傳聞西洛名千變，排釋東風恨萬端。", "茂苑去天真尺五，羨君花信報平安。"]'),
('3be20dc0-ee85-46fc-971b-1e6b92d87059','芍藥','許及之','宋','宋诗','song-poetry','','[]','揚州千葉舊生涯，詩到坡仙正復葩。',64,'全唐诗/poet.song.153000.json','["揚州千葉舊生涯，詩到坡仙正復葩。", "喜見故家翻瑞藥，送將新句續名花。", "日高髲鬀醺含露，時樣梳粧肉映紗。", "窈窕留春春不住，詩翁留得鬢邊華。"]'),
('882d9aa7-380d-488a-9e31-c4d731381c1d','再用韻','許及之','宋','宋诗','song-poetry','','[]','莫問無涯及有涯，眼前萬綠替千葩。',64,'全唐诗/poet.song.153000.json','["莫問無涯及有涯，眼前萬綠替千葩。", "故人訪我跫然喜，小閣留春聖得花。", "美酒急傾門候鑰，清歌未徹燭籠紗。", "匆匆似此頻能過，猶勝逢人說夢華。"]'),
('6dd3d28f-8415-40bd-a1a9-fe930ed66389','三用韻','許及之','宋','宋诗','song-poetry','','[]','綠遍山顛與水涯，苦吟且不到春葩。',64,'全唐诗/poet.song.153000.json','["綠遍山顛與水涯，苦吟且不到春葩。", "新篁已接三竿日，紅藥猶開四月花。", "好句更煩銜兩袖，嫩寒猶覺怯重紗。", "留連小飲無須醉，明月翩翩扈翠華。"]'),
('eea7b666-4e1a-4fc2-93de-b1d1e855a86f','花藥相接可觀復用韻','許及之','宋','宋诗','song-poetry','','[]','浄盡天香溢夏寒，滿奩誰擲狡仙丹。',64,'全唐诗/poet.song.153000.json','["浄盡天香溢夏寒，滿奩誰擲狡仙丹。", "洛花不逐林花老，禁藥猶堪木藥團。", "試問丁香和恨結，何如萱草破憂端。", "翠屏紅粉腰如束，我是村中老謝安。"]'),
('fcc15ce1-a811-4de6-8fb8-7c5d6f7ba4ed','傳芍藥復用韻','許及之','宋','宋诗','song-poetry','','[]','階藥留春逗晚寒，鬢絲敢傍臉霞丹。',64,'全唐诗/poet.song.153000.json','["階藥留春逗晚寒，鬢絲敢傍臉霞丹。", "肯分騎鶴紅千葉，喜見盤龍綠一團。", "妖格流傳如有恨，狂香橫出亦無端。", "慇懃爲換瓶中水，排比窗前兩行安。"]'),
('ef74a1bc-48a9-43ae-8133-9cf3be912973','和人惠白蓮花','許及之','宋','宋诗','song-poetry','','[]','碧蓮花發夢灣磯，鶴骨難教厚祿肥。',64,'全唐诗/poet.song.153000.json','["碧蓮花發夢灣磯，鶴骨難教厚祿肥。", "夜月擎來雙掌露，曉風拂動六銖衣。", "漁歌過後香猶濕，鷺影移時雪欲霏。", "風月既爲專一壑，茅茨何自有光輝。"]'),
('43e92a8e-a39e-4ddd-87c5-c5fe5acfb743','池蓮','許及之','宋','宋诗','song-poetry','','[]','一灣清碧繞中阿，萬柄香紅映麴波。',64,'全唐诗/poet.song.153000.json','["一灣清碧繞中阿，萬柄香紅映麴波。", "不道龜魚長受庇，只欣鷗鷺數相過。", "機心久與塵俱息，警句元無趣自多。", "病起情悰聊徙倚，何人解唱野塘歌。"]'),
('9358ccbd-cfed-4c4a-82ee-59eb269737b6','鑿池添種荷花','許及之','宋','宋诗','song-poetry','','[]','累石防花拾棄材，鑿池種藕白餘苔。',64,'全唐诗/poet.song.153000.json','["累石防花拾棄材，鑿池種藕白餘苔。", "游鯈剩喜波光闊，飛鷺似知人意來。", "已見圓荷浮小葉，正須細雨熟黄梅。", "莫言舊隠無多景，一派清泉手自開。"]'),
('db662846-79a0-4400-9502-0b5c47e24c9c','玉簪花','許及之','宋','宋诗','song-poetry','','[]','琉璃布地綠愔愔，苗長藍田夜照林。',64,'全唐诗/poet.song.153000.json','["琉璃布地綠愔愔，苗長藍田夜照林。", "雪色能香開有璞，玉光未拆盍成簪。", "不登雲髻尤孤潔，長浸銅壺更久禁。", "梅與水仙流品外，幽蘭相友是同心。"]'),
('893c8b75-bbcc-446a-a065-8655ed66c63e','秋萱','許及之','宋','宋诗','song-poetry','','[]','說著宜男已可羞，移栽老圃且忘憂。',64,'全唐诗/poet.song.153000.json','["說著宜男已可羞，移栽老圃且忘憂。", "傳爲麝種生來別，喚作鹿葱元是愁。", "幸脫炎威纔過夏，何緣冷落尚宜秋。", "國香天且難拘管，過眼空花一笑休。"]'),
('f0b76a3a-7fc4-4d92-9024-a2d0640fee84','鴈來紅','許及之','宋','宋诗','song-poetry','','[]','非花非葉艷茸茸，鴈未來時已自紅。',64,'全唐诗/poet.song.153000.json','["非花非葉艷茸茸，鴈未來時已自紅。", "多似錦衣明晝繡，好同旌節種秋風。", "雞冠麤俗難爭長，金鳳低徊漫作叢。", "誰道後庭遺恨曲，龍蟠王氣正豪雄。"]'),
('8a131dd7-6171-452f-b9f2-96b7fc10ff61','李若兄菊詩同社久已嗟賞賡和屬蒙寫寄仍用韻以致予奉祠之喜予兩年從金陵覓菊栽而一種至今著蕊未開豈所謂晚節香者耶次韻奉酬  其一','許及之','宋','宋诗','song-poetry','','[]','滿地金錢買斷秋，晚年安得有窮愁。',64,'全唐诗/poet.song.153000.json','["滿地金錢買斷秋，晚年安得有窮愁。", "小園不負長寒眼，佳客自疎新白頭。", "一種最開陶逕晚，兩年曾向蔣山求。", "肯能過訪同心賞，猶勝傳聲互答酬。"]'),
('1226c4f8-6fc0-42b0-a9a0-47642f316810','李若兄菊詩同社久已嗟賞賡和屬蒙寫寄仍用韻以致予奉祠之喜予兩年從金陵覓菊栽而一種至今著蕊未開豈所謂晚節香者耶次韻奉酬  其二','許及之','宋','宋诗','song-poetry','','[]','四體支吾兩鬢秋，一生知足百無愁。',64,'全唐诗/poet.song.153000.json','["四體支吾兩鬢秋，一生知足百無愁。", "洞霄香火手加額，太玉山園茅蓋頭。", "歸去來兮交未息，不知我者謂何求。", "若人共說無生話，一句拋來一句酬。"]'),
('00bd0f46-9a14-4ee1-aa26-63f94917c875','次韻章君濟黄元章二廣文種竹建康學宮','許及之','宋','宋诗','song-poetry','','[]','城雲一塢碧雲深，亦許分青到泮林。',64,'全唐诗/poet.song.153000.json','["城雲一塢碧雲深，亦許分青到泮林。", "移去檢書涓醉日，種來挾策較分陰。", "細看直節難教改，設有繁霜不受侵。", "二妙育才如此竹，惜無健筆與長吟。"]'),
('981c99d9-d3e0-46c2-9590-5d39fdad0d48','即事併寫和質弟詩呈似','許及之','宋','宋诗','song-poetry','','[]','新綠愔愔長茂材，嫩流漠漠養深苔。',64,'全唐诗/poet.song.153000.json','["新綠愔愔長茂材，嫩流漠漠養深苔。", "一梭金影緡蠻過，半纈花光剝啄來。", "檻竹鳴邊垂粉籜，池萍缺處落肥梅。", "閒中偏得園林趣，更覺清和意象開。"]'),
('7c4f7272-205d-418d-b6e1-61f3af12f787','檢校園課濟叔又送花栽欣然有作','許及之','宋','宋诗','song-poetry','','[]','雨餘扶杖入蒼苔，檢校園工有品裁。',64,'全唐诗/poet.song.153000.json','["雨餘扶杖入蒼苔，檢校園工有品裁。", "緩引瓜苗教傍架，旋齊菊杪要平臺。", "出牆新竹矜施粉，立水高荷勸把杯。", "莫訝小園饒勝事，故人續續送花栽。"]'),
('b1055e73-c457-434d-a668-1fdac77f0b57','蔣肖李潘才叔和檢校園課之什再用韻爲謝','許及之','宋','宋诗','song-poetry','','[]','隨意篇章落海苔，瓊瑶欲報不知裁。',64,'全唐诗/poet.song.153000.json','["隨意篇章落海苔，瓊瑶欲報不知裁。", "青蒲細草來齋几，白雪陽春走皂臺。", "夢裏勳名槐是國，閒中活計芥爲杯。", "吟哦蔣徑潘江句，淺白深紅手自栽。"]'),
('9ac02941-8a1b-4983-89a0-4b52f9281143','肖李才叔和篇末章有青蒲自是公家物之語再用韻爲謝','許及之','宋','宋诗','song-poetry','','[]','踏破先生客位苔，詩仙鳳沼得重裁。',64,'全唐诗/poet.song.153000.json','["踏破先生客位苔，詩仙鳳沼得重裁。", "連城更枉捐雙璧，二妙真堪共一臺。", "蠅到成時元誤筆，蛇因添後失持杯。", "勸君休話青蒲事，妄想根苗莫更栽。"]'),
('30cf6d25-4e1c-421c-abc6-4fd434d31906','次韻毛漳州遣价爲壽二首  其一','許及之','宋','宋诗','song-poetry','','[]','漳州遠爲故人東，問訊深憐臭味同。',64,'全唐诗/poet.song.153000.json','["漳州遠爲故人東，問訊深憐臭味同。", "喜可寒冬耕灞滻，吟堪小麥熟崆峒。", "賤生已覺年駸暮，遠祝應難日再中。", "願老洞霄香火吏，餘齡猶得效呼嵩。"]'),
('de37a4ee-6e9c-4954-8966-2d17fa7eaad4','次韻毛漳州遣价爲壽二首  其二','許及之','宋','宋诗','song-poetry','','[]','充位無功得放歸，淵明若在恥吾師。',64,'全唐诗/poet.song.153000.json','["充位無功得放歸，淵明若在恥吾師。", "舊交動色知毛檄，故里分甘到董帷。", "顧我已淪訶譴域，如君合建太平基。", "競傳報政趨嚴召，遠業真堪濟此時。"]'),
('d3474317-c89e-457a-8c70-4c968abd337a','爲轉庵壽二首  其一','許及之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','却喜漳南解秩歸，天教慰藉老朋知。',64,'全唐诗/poet.song.153000.json','["却喜漳南解秩歸，天教慰藉老朋知。", "巷南巷北游從舊，浙右浙東賡唱詩。", "上閣有題皆得和，西湖無路可陪時。", "年顔相去追隨得，難老如公壽更頤。"]'),
('560bd3bf-ce62-4d47-8d49-1938fde61fa5','爲轉庵壽二首  其二','許及之','宋','宋诗','song-poetry','','[]','歲歲新陽喜仲旬，兩家兒輩作生辰。',64,'全唐诗/poet.song.153000.json','["歲歲新陽喜仲旬，兩家兒輩作生辰。", "下生彌勒遲三日，共約梅花作故人。", "未許同龕供佛事，只須共載接車茵。", "相先壽語須齊和，滿酌吾家太玉春。"]'),
('3e7331f3-ecf6-483d-bd74-ab530b44f5e1','高少卿輓詞','許及之','宋','宋诗','song-poetry','','[]','剖竹乘軺課最多，班高惟月正透迤。',64,'全唐诗/poet.song.153000.json','["剖竹乘軺課最多，班高惟月正透迤。", "千齡聖主難逢際，九袠慈親奈老何。", "尚擬鳴珂還里衖，俄傷埋玉向山阿。", "宣仁忠節平生願，有子巍登進士科。"]'),
('858d1391-0516-4797-9356-a52775d71bb9','蔡知閣輓詞','許及之','宋','宋诗','song-poetry','','[]','抱負平生是樸忠，發揮不盡古人風。',64,'全唐诗/poet.song.153000.json','["抱負平生是樸忠，發揮不盡古人風。", "名藩多歷爲民福，上閣頻輸在帝衷。", "勳業有期方感會，哀榮不恨劇初終。", "靈峰樹杪龜趺出，無愧銘辭屬蔡公。"]'),
('1e8488a2-5f53-4704-8fde-58b2b02d6a71','親家張舍人輓詞  其一','許及之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','忍看丹旐引靈輀，尚想祥華進止時。',64,'全唐诗/poet.song.153000.json','["忍看丹旐引靈輀，尚想祥華進止時。", "無復短檠親教子，空餘滿篋舊題詩。", "陰功會即佳城兆，顯刻猶須幼婦碑。", "小殯西湖湖上寺，冷雲秋露不勝悲。"]'),
('d1b117b4-c861-419e-9679-cc1350294c49','親家張舍人輓詞  其二','許及之','宋','宋诗','song-poetry','','[]','憶曾伯仲共論文，迭和壎箎自不羣。',64,'全唐诗/poet.song.153000.json','["憶曾伯仲共論文，迭和壎箎自不羣。", "尚以竹林憐小阮，肯令新婦配參軍。", "登樓無計追王粲，載酒空煩過子雲。", "幸有諸郎傳素業，勉旃猶足振前聞。"]'),
('81fd8ee0-b09c-4ecd-8e5e-1d77e5c4870f','輓承事黄公詞','許及之','宋','宋诗','song-poetry','','[]','膠庠衣鉢是青氈，付與兒曹自勉旃。',64,'全唐诗/poet.song.153000.json','["膠庠衣鉢是青氈，付與兒曹自勉旃。", "鼎級科名彰父教，著庭勳績見家傳。", "千鍾合使榮三釜，一品終當貴九泉。", "留却無窮風木恨，悲笳嗚咽晚春天。"]'),
('043181a9-7199-443a-8bd1-bc842ecf8956','錢致政輓詞','許及之','宋','宋诗','song-poetry','','[]','教子全功次第成，吾鄉錢氏竇家聲。',64,'全唐诗/poet.song.153000.json','["教子全功次第成，吾鄉錢氏竇家聲。", "善根植得橋梁固，心地均教役使平。", "銅墨遠從欣養志，銀緋勇返了遺榮。", "哀榮壽考無堪恨，行道稱嗟淚自傾。"]'),
('fe84236d-4fbd-42fa-9763-2ceea2219f17','劉和州輓詞','許及之','宋','宋诗','song-poetry','','[]','風姿醖藉發陽和，議論崢嶸砥柱波。',64,'全唐诗/poet.song.153000.json','["風姿醖藉發陽和，議論崢嶸砥柱波。", "先見不爲時宰信，孤忠惟是聖心多。", "兩州惠愛逢人說，萬里功名奈病何。", "期待自慙無補報，忍觀埋玉北山阿。"]'),
('971300b9-c445-49be-952d-45193e039e7b','鄭通判同年輓詞  其一','許及之','宋','宋诗','song-poetry','','[]','人物吾鄉行秘書，功名末路坐題輿。',64,'全唐诗/poet.song.153000.json','["人物吾鄉行秘書，功名末路坐題輿。", "只教副墨傳蠻徼，不得雌黄到石渠。", "臨事孰如仁者勇，著書猶是道之餘。", "推尊文行銘辭好，無愧當年歎起予。"]'),
('186f257c-d4c7-424d-b06a-3def73a993ee','鄭通判同年輓詞  其二','許及之','宋','宋诗','song-poetry','','[]','驚心同榜渺參辰，回首龍飛四十春。',64,'全唐诗/poet.song.153000.json','["驚心同榜渺參辰，回首龍飛四十春。", "不憗此翁天實惜，欲論心事我誰親。", "百年風月歸吟筆，一代儀型落後塵。", "正爾棘心吹淚苦，石塘東望更沾巾。"]'),
('401a8b8f-dfc8-440c-aacf-dea86279e46f','鄭光宗節使輓詞','許及之','宋','宋诗','song-poetry','','[]','孝廟祥刑首選掄，行藏何愧百年身。',64,'全唐诗/poet.song.153000.json','["孝廟祥刑首選掄，行藏何愧百年身。", "共知草木威名舊，親見旌麾號令新。", "登陸政成俄告老，建旄好在奄歸真。", "傳家有子無遺恨，千古佳城澤後人。"]'),
('09a53142-7b92-4c0e-8008-48761d25ed09','陳紫微輓詞','許及之','宋','宋诗','song-poetry','','[]','三生竹素一臞仙，六藝波瀾萬口傳。',64,'全唐诗/poet.song.153000.json','["三生竹素一臞仙，六藝波瀾萬口傳。", "能使聲名垂宇內，不教官職副生前。", "松階顯揭新阡表，宣室深知舊學賢。", "憶賦桐君贈予別，忍吟薤露輓公篇。"]'),
('505b4d6e-4875-4004-96da-39d9b475eaef','侯機宜輓詞三首  其一','許及之','宋','宋诗','song-poetry','','[]','世取名科耀故鄉，君家顯祖屹相望。',64,'全唐诗/poet.song.153000.json','["世取名科耀故鄉，君家顯祖屹相望。", "將雛近喜重偕計，有子先登服義方。", "著從事衫元漫仕，入元戎幕已交章。", "頭風正待陳琳檄，熟路輕車痛折箱。"]'),
('87b6a2c4-6395-4cb2-b1a9-9b28ae3bb8de','侯機宜輓詞三首  其二','許及之','宋','宋诗','song-poetry','','[]','豈以姻親篤故情，最憐意氣感平生。',64,'全唐诗/poet.song.153000.json','["豈以姻親篤故情，最憐意氣感平生。", "身居城市如專壑，家蓄圖書得主名。", "滿擬歸田諳笑語，何期中路隔幽明。", "有兒萬事無堪恨，待勒銘詩作世程。"]'),
('73aecde3-6a23-4f6c-8f6b-d707916f1146','侯機宜輓詞三首  其三','許及之','宋','宋诗','song-poetry','','[]','掀髯握手話心期，錄錄儔中獨見知。',64,'全唐诗/poet.song.153000.json','["掀髯握手話心期，錄錄儔中獨見知。", "官職有慚公過許，行藏無據我何爲。", "直書實行人能讀，厚德深功世莫窺。", "有子傳家吾不恨，西風吹袂涕垂頤。"]'),
('3029b747-1c02-406c-8754-656669429b15','周和叔輓詞','許及之','宋','宋诗','song-poetry','','[]','不煩月旦課鄉評，少日聲名老更成。',64,'全唐诗/poet.song.153000.json','["不煩月旦課鄉評，少日聲名老更成。", "百里恩波東淛水，兩州遺愛蜀江城。", "操持堅徹神明懼，精爽全歸父母生。", "子有筆端公不死，故交零落我傷情。"]'),
('902b84ec-d51b-4834-8cb8-dd6bde252f92','轉庵輓詞','許及之','宋','宋诗','song-poetry','','[]','無復從容唱和詩，忍爲惻愴輓歌詞。',64,'全唐诗/poet.song.153000.json','["無復從容唱和詩，忍爲惻愴輓歌詞。", "生前秋月春花了，身後高山流水知。", "小阮竹林思步武，仲芳蒿里得追隨。", "腰金埋玉終塵土，萬卷千篇倚二兒。"]'),
('073237ae-70f9-49ed-932a-ef65723b6224','善士嚴明仲輓詞','許及之','宋','宋诗','song-poetry','','[]','清風元在釣臺邊，分派東嘉世有傳。',64,'全唐诗/poet.song.153000.json','["清風元在釣臺邊，分派東嘉世有傳。", "教子以經無盡藏，活人爲德不唐捐。", "年登九九方開袠，心契三三即了禪。", "壽得考終稱善士，合將哀些表新阡。"]'),
('cbf82235-3af1-4232-ac5d-112de4e053a3','萬侍郎母夫人錢氏輓詞','許及之','宋','宋诗','song-poetry','','[]','親歸兒住可勝悲，兒第親存各不知。',64,'全唐诗/poet.song.153000.json','["親歸兒住可勝悲，兒第親存各不知。", "一世苦心天乞與，百年榮養聖垂慈。", "共傳義激投簪語，合見恩除從橐時。", "不及聯書朱氏母，可憐惟賦輓歌詞。"]'),
('9fc35f6b-5412-47ff-b01d-1f0234cc4a07','夫人滕氏輓詞','許及之','宋','宋诗','song-poetry','','[]','升堂憶昨拜慈容，京兆平反一笑中。',64,'全唐诗/poet.song.153000.json','["升堂憶昨拜慈容，京兆平反一笑中。", "可但三從多懿範，了知百念積陰功。", "松階猛乞榮歸養，吉國真如擅考終。", "千古難消吹棘恨，可堪丹旐卷春風。"]'),
('4c24c68d-dd13-47b8-9a71-c1351ad4fe40','代上皇太子壽二十韻','許及之','宋','宋诗','song-poetry','','[]','闔闢乾坤迥，胚腪曆數長。',240,'全唐诗/poet.song.153000.json','["闔闢乾坤迥，胚腪曆數長。", "較論今鮮儷，詣絕古非常。", "八袠尊堯典，千齡格舜裳。", "孫枝綿奕葉，國本係元良。", "南極昭穹覆，東儲應壽昌。", "九秋開令節，五日屆重陽。", "照曜辰儀肅，氤氳甲觀祥。", "玉巵傳錫嘏，瑶樂奏稱觴。", "茅土仙潢潤，芝蘭寶砌芳。", "元勳來閥閲，嘉耦奉尊章。", "慶事川方至，歡呼殿未央。", "恭惟天繼體，仰止日重光。", "擬把涓埃報，難將算數量。", "皇圖恢遠馭，壽域振遐荒。", "寢事龍樓問，班陪虎胄行。", "神明推大尹，惠養式羣方。", "朝夕淵沖地，闚瞻簡樂堂。", "不能鞭朽鈍，何物介陵岡。", "再拜占霄象，千門祝夜香。", "兩宮千萬歲，三聖共無疆。"]'),
('8ea453d4-ae65-44a7-aca7-e232132afd22','又代賀十韻','許及之','宋','宋诗','song-poetry','','[]','南極昭穹象，東儲慶壽昌。',120,'全唐诗/poet.song.153000.json','["南極昭穹象，東儲慶壽昌。", "千秋符季月，五日近重陽。", "銀榜辰儀肅，銅吹甲觀祥。", "兩宮開燕喜，萬國慶元良。", "競指椿爲算，爭持菊泛觴。", "恭惟天廣大，仰止日輝光。", "繼體觀行健，重輪耀有常。", "自然高宇宙，何物介陵岡。", "監古慙能讀，分僚忝接行。", "三王真有道，更欲祝綿長。"]'),
('f45fa284-99a8-4143-97ab-b4b11b61471c','上左丞相壽二十韻','許及之','宋','宋诗','song-poetry','','[]','闔闢乾坤迥，甄陶物象新。',240,'全唐诗/poet.song.153000.json','["闔闢乾坤迥，甄陶物象新。", "舜絃熏入治，商鼎味還淳。", "天貺方垂節，崧高已降神。", "清明開造化，精祲下星辰。", "謙損祇縫掖，尊嚴絕縉紳。", "怯惟聞己過，勇豈遜師仁。", "補衮工夫細，垂裳寵渥頻。", "熱官無倖位，寒士有通津。", "水旱猶親奏，封章要廣陳。", "棟梁須偃植，海嶽待涓塵。", "自昔觀前輩，于今邁等倫。", "調和全玉燭，鼓舞在洪鈞。", "薄海歸洪軸，中原望帝宸。", "兩宮三聖日，四海一家春。", "少倚遐衝折，重看壽域均。", "無官酬竹帛，有節擬松筠。", "曉日馳中使，流霞出九旻。", "敬爲丞相壽，恭上太夫人。", "盛德寧無種，長年宛似親。", "小人因有母，慚愧器輪囷。"]'),
('b0b8ef0e-83f4-4138-a9a6-9da7b037ecdf','上梁丞相壽二十韻','許及之','宋','宋诗','song-poetry','','[]','千載風雲會，三生柱石緣。',240,'全唐诗/poet.song.153000.json','["千載風雲會，三生柱石緣。", "罕聞流渚旦，同在降崧年。", "天意開皇極，神謀屬鉅賢。", "中和垂節後，嗜欲兆開先。", "象應魁三近，聲蜚第一傳。", "十年登鼎鉉，四海入陶甄。", "輕重朝廷寄，安危將相權。", "朔方頻借問，南國小回旋。", "再入儀刑肅，周詢眷倚專。", "折衝聲色外，燮理冕旒前。", "照曜冰山泮，調和玉燭圓。", "帝方張撻伐，天欲靖烽烟。", "機會寧容髮，功成即濟川。", "長城端有託，壽域定無邊。", "不用霞觴祝，唯應寶札編。", "昇平天下宰，陰德地行仙。", "霽色歸桃李，韶光並管絃。", "深爲修禊日，全似浴沂天。", "但樂垂裳化，難酬補衮妍。", "清風時入抱，聊寫穆如篇。"]'),
('dd712209-abeb-407a-882c-ce23870a232b','上安撫程給事十六韻','許及之','宋','宋诗','song-poetry','','[]','臺省儀型舊，垣扉寵渥新。',192,'全唐诗/poet.song.153000.json','["臺省儀型舊，垣扉寵渥新。", "詞章關造化，論議藴經倫。", "去國悲風木，流年感隙塵。", "未教居鼎鼐，亦合上星辰。", "何自占雙使，從誰問大鈞。", "熊湘辰告入，牛斗夜光陳。", "禮樂須賢帥，湖山要主人。", "一言九重寤，八縣十州春。", "拾穗歌時熟，投醪味德醇。", "燕閒餘畫㦸，談笑且綸巾。", "早晚登黄閣，聲猷動紫宸。", "有儒嗟濩落，無路話邅迍。", "憶拜編書賜，祇憐負弩身。", "或疑千里馬，曾遇九方歅。", "北斗言瞻切，西山入夢頻。", "登臨冀軒豁，未敢歎輪囷。"]'),
('853c6e5d-a0b0-47ba-833f-4ffdc71a4380','上辛安撫二十韻','許及之','宋','宋诗','song-poetry','','[]','開闢重華旦，胚胎間世賢。',240,'全唐诗/poet.song.153000.json','["開闢重華旦，胚胎間世賢。", "雲龍時際會，星鳳睹爭先。", "天授歸三傑，神謀效一編。", "宏謨驅固陋，餘論細雕鎸。", "詔旨傾臚句，山呼動奏篇。", "干霄須造化，惟月進班聯。", "有客占星次，逢人問日邊。", "江湖煩鎮撫，壤地屈盤旋。", "談笑潢池浄，生成壁壘堅。", "丈夫真細事，餘子敢差肩。", "黄屋深知切，青雲寵渥駢。", "即歸調鼎鉉，少駐斸龍泉。", "更治今馮翊，重歸舊潁川。", "載塗明積雪，嗣歲卜豐年。", "封殖棠陰盛，歡迎竹馬鮮。", "恩波行處足，威譽向來傳。", "此獨瘡痍甚，方疑雨露偏。", "禁通鄰邑粟，費減月樁錢。", "齋戒逾三日，遭逢有二天。", "執鞭吾所慕，負弩敢驅前。"]'),
('76c5e69e-b0be-4c72-bc3e-5b6e69eec41b','上周尚書內翰承旨二十韻','許及之','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','弱水蓬萊遠，羣山岱嶽高。',240,'全唐诗/poet.song.153000.json','["弱水蓬萊遠，羣山岱嶽高。", "塵埃千障隔，景行寸心勞。", "摸索知何自，摳趨苦未遭。", "銅章披宿霧，藻鑒炳秋毫。", "穹壤懸鵬鷃，篇章抵鴈羔。", "斯文標正脈，輿論凜時髦。", "勇退關吾道，留行切帝褒。", "風雲開壯觀，舟楫際洪濤。", "劍履昭魁象，詞瀾卷巨鼇。", "合宮陳縟典，華蓋粲星旄。", "霽日明黄道，祥風動赭袍。", "恩波榮赦草，顔咫醉仙桃。", "麻冊追盤誥，詩歌逼頌騷。", "人方期補衮，功豈在揮毫。", "地禁承中旨，天官冠列曹。", "儀型喜頗牧，步武接夔皋。", "蚤晚登三事，乾坤倚一陶。", "途長須驥足，用拙匪牛刀。", "造請神先索，推敲癢莫搔。", "未嗟聞道晚，終待郢斤操。"]'),
('c8add1be-389a-4b89-af17-11d46cfaf56d','上運使蘇大卿十六韻','許及之','宋','宋诗','song-poetry','','[]','當代推先正，斯文倚廢興。',192,'全唐诗/poet.song.153000.json','["當代推先正，斯文倚廢興。", "表章逢聖主，衣鉢見孫曾。", "操履渾圭璧，行藏動準繩。", "太羹元薄味，積水自增冰。", "洛誦傳瑰墨，雞林織寶繒。", "六卿聊率屬，三事即延登。", "一自雙星出，重煩四牡乘。", "周知民疾苦，密訪吏賢能。", "已見江西化，都爲道院稱。", "夷塗終妥帖，揆路始飛騰。", "後進思親炙，今吾有服膺。", "百年能幾見，一語願師承。", "令弩方危脫，公堂許驟升。", "暗中慙摸索，胸次漫崚嶒。", "末俗惟同調，初心只自憎。", "可能憐鷽鷃，隨意亦鯤鵬。"]'),
('2e5dccb7-23d6-4a06-9cbf-93e90cd17b7e','見提刑鞏大監三十韻','許及之','宋','宋诗','song-poetry','','[]','夙借屏星映，曾憐坐客寒。',288,'全唐诗/poet.song.153000.json','["夙借屏星映，曾憐坐客寒。", "扁舟違逆水，方丈渺三韓。", "分隔懸穹壤，心馳乏羽翰。", "熒煌長在望，歲月凜奔湍。", "凡骨思佺訣，師資待郢墁。", "把文留篋笥，洗眼誦琅玕。", "轍敢窮途慟，冠期結綬彈。", "苦無蒼玉佩，絕憶紫金丹。", "往絕修門入，爭先要路看。", "飛騰寧有策，遇合自相歡。", "獻納君王問，施行宇宙寬。", "前星開尹幕，列宿炳朝端。", "賀老聊爲監，嚴公合從官。", "調官因有便，典謁亦曾干。", "不得瞻丰采，無由出肺肝。", "姓名煩摸索，蹤跡自蹣跚。", "未有三千牘，那能九萬摶。", "抱關從苑候，失步向邯鄲。", "繼憶專城去，俱興歛惠歎。", "第聞盤錯舊，不見剸裁難。", "帝眷從更治，民風要飽觀。", "甫傳光禮樂，已著畫衣冠。", "浙水東西接，恩波晝夜瀾。", "去天鄰杜曲，近日即長安。"]'),
('36c94e03-30ba-4834-8d4c-023ff225f296','別毛質夫省宣撫丘同知訪都督張知院十韻代簡','許及之','宋','宋诗','song-poetry','','[]','交契三生在，違離百念休。',120,'全唐诗/poet.song.153000.json','["交契三生在，違離百念休。", "杜門煩枉駕，力疾喜登樓。", "擊節聽高論，持杯散暮愁。", "諸公爭屈致，故里可淹留。", "科第休云晚，行藏却自由。", "安邊須遠畧，造膝待前籌。", "雨泊中川嶼，風帆古括州。", "知津君已熟，惜別我何憂。", "京口留青眼，澄江正白頭。", "或紓知己問，已負殺身酬。"]'),
('4f46b48b-edaa-487c-ba07-efca36a9626b','太上皇后閤春帖子  其一','許及之','宋','宋诗','song-poetry','','[]','壽擬南山祝，春從北斗回。',24,'全唐诗/poet.song.153000.json','["壽擬南山祝，春從北斗回。", "物華欣向泰，厚德發生來。"]'),
('1de78a50-f3eb-49f4-bc4f-891c057b338b','太上皇后閤春帖子  其二','許及之','宋','宋诗','song-poetry','','[]','母道齊皇極，韶光傍壽觴。',24,'全唐诗/poet.song.153000.json','["母道齊皇極，韶光傍壽觴。", "徽音家慶集，隨輦奉尊章。"]'),
('0e208a3c-63e3-45ef-af46-6c6847a2a13d','太上皇后閤春帖子  其三','許及之','宋','宋诗','song-poetry','','[]','風簾回翡翠，冰研伴蟾蜍。',24,'全唐诗/poet.song.153000.json','["風簾回翡翠，冰研伴蟾蜍。", "親寫迎春帖，真符太上書。"]'),
('cf991fc1-c57a-43b7-8e98-9afbeff47da6','太上閤端午帖子  其一','許及之','宋','宋诗','song-poetry','','[]','自得廣成道，長居不老天。',24,'全唐诗/poet.song.153000.json','["自得廣成道，長居不老天。", "底須桃辟惡，何用木延年。"]'),
('df615c9f-d0fb-4f4b-890d-b33f40529809','太上閤端午帖子  其二','許及之','宋','宋诗','song-poetry','','[]','人艾休教采，仙丹久養成。',24,'全唐诗/poet.song.153000.json','["人艾休教采，仙丹久養成。", "六宮爭結縷，再拜學長生。"]'),
('07c983db-ec67-4939-bf1a-005674f5167d','太上閤端午帖子  其三','許及之','宋','宋诗','song-poetry','','[]','柈獻千年實，杯行九節蒲。',24,'全唐诗/poet.song.153000.json','["柈獻千年實，杯行九節蒲。", "至尊親上壽，家慶列成圖。"]'),
('3ebde9ba-c08d-4fb8-bd8f-16dc41635254','聖壽閤端午帖子  其一','許及之','宋','宋诗','song-poetry','','[]','有德天同壽，無爲日更長。',24,'全唐诗/poet.song.153000.json','["有德天同壽，無爲日更長。", "每逢端午節，雙上萬年觴。"]'),
('5c367572-2be0-4fa7-a172-a7e86a337e88','聖壽閤端午帖子  其二','許及之','宋','宋诗','song-poetry','','[]','畫扇迎雙鳳，輕衣拂六銖。',24,'全唐诗/poet.song.153000.json','["畫扇迎雙鳳，輕衣拂六銖。", "太清元有籙，抱朴不須符。"]'),
('7103e026-56ae-4d76-a438-c0e1ee29cd00','聖壽閤端午帖子  其三','許及之','宋','宋诗','song-poetry','','[]','繞臂長生縷，當門五色絲。',24,'全唐诗/poet.song.153000.json','["繞臂長生縷，當門五色絲。", "榴花看結子，葉葉在孫枝。"]'),
('d4e0cb33-6f9f-4d50-b777-5a230db69956','題惠崇小景  其一','許及之','宋','宋诗','song-poetry','','[]','寒林幾吹折，凍柳不勝垂。',24,'全唐诗/poet.song.153000.json','["寒林幾吹折，凍柳不勝垂。", "老去機心熟，驚鷗莫浪疑。"]'),
('01e6d504-521a-47be-834a-51fa627c1371','題惠崇小景  其二','許及之','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','崔嵬吾肺腑，面目似廬山。',24,'全唐诗/poet.song.153000.json','["崔嵬吾肺腑，面目似廬山。", "江上風濤穩，扁舟得往還。"]'),
('7dbd81cd-f64c-4a8f-acb8-10aff07362e9','題惠崇小景  其三','許及之','宋','宋诗','song-poetry','','[]','舒徐春晝永，取次小桃紅。',24,'全唐诗/poet.song.153000.json','["舒徐春晝永，取次小桃紅。", "獨爵把枝穩，矜呼立晚風。"]'),
('04ca5bc3-c64a-4144-93a3-749e7b0b6b99','題惠崇小景  其四','許及之','宋','宋诗','song-poetry','','[]','兩蛙隨步武，先後得位置。',24,'全唐诗/poet.song.153000.json','["兩蛙隨步武，先後得位置。", "不作渴雨鳴，豈不賢鼓吹。"]'),
('acafc226-7e1a-4bf7-be1c-7e8eaff51051','題文與可山水','許及之','宋','宋诗','song-poetry','','[]','疎篠寒林手，文家富襪材。',24,'全唐诗/poet.song.153000.json','["疎篠寒林手，文家富襪材。", "片縑雲氣足，彷彿認蓬萊。"]'),
('82904846-4519-4ce5-80cf-15b303c1da0e','題洪子恂所畫盤洲圖','許及之','宋','宋诗','song-poetry','','[]','林塘天遺得，花木地宜栽。',24,'全唐诗/poet.song.153000.json','["林塘天遺得，花木地宜栽。", "細紀平泉咏，揮毫落海苔。"]'),
('4d277275-7198-4760-bab7-d019a4110426','題車盤圖','許及之','宋','宋诗','song-poetry','','[]','牛磨人俱轉，車旋水即流。',24,'全唐诗/poet.song.153000.json','["牛磨人俱轉，車旋水即流。", "爭如霖雨足，所至息人牛。"]'),
('a39a16ea-67d7-4968-bd43-3604cbdc0455','歸牧圖','許及之','宋','宋诗','song-poetry','','[]','爵祿不入心，牛肥了耕稼。',24,'全唐诗/poet.song.153000.json','["爵祿不入心，牛肥了耕稼。", "綠陰生晚烟，歸來兩閒暇。"]'),
('076027dc-1d46-44b2-8a80-a6a68bc03ec2','題水石翎毛','許及之','宋','宋诗','song-poetry','','[]','此君已可人，更著水石映。',24,'全唐诗/poet.song.153000.json','["此君已可人，更著水石映。", "水禽穿林來，相呼復相應。"]'),
('f43ac9fe-906e-40cf-8cec-808ac3e1c942','題邊魯生花木翎毛四首  其一','許及之','宋','宋诗','song-poetry','','[]','綠垂朱雀柳，雙燕不勝春。',24,'全唐诗/poet.song.153000.json','["綠垂朱雀柳，雙燕不勝春。", "泥落空梁語，之人竟殺身。"]'),
('45c0578d-f4b8-4375-8361-2aa1b1de5808','題邊魯生花木翎毛四首  其二','許及之','宋','宋诗','song-poetry','','[]','南國枇杷熟，卑枝結子多。',24,'全唐诗/poet.song.153000.json','["南國枇杷熟，卑枝結子多。", "一雙拖白練，飛墮綠林阿。"]'),
